fn run_session_queue(args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    flags.expect_positionals("session queue", 0)?;
    let state_dir = session_state_dir_from_flags(&flags)?;
    session_queue_payload(&state_dir)
}

fn session_queue_payload(state_dir: &Path) -> CliOutcome<Value> {
    let now_ms = current_unix_ms();
    let health = session_queue_health(state_dir, now_ms, SESSION_DAEMON_REQUEST_TIMEOUT_MS)?;
    let status = health
        .get("status")
        .and_then(Value::as_str)
        .ok_or_else(|| {
            CliError::new(
                ErrorKind::RuntimeNotRunning,
                "session_queue_status_missing",
                "session queue could not read queue health status",
                &["request_queue"],
            )
        })?;
    let can_enqueue = match status {
        "clear" | "active" => true,
        "needs_attention" => false,
        other => {
            return Err(CliError::new(
                ErrorKind::RuntimeNotRunning,
                "session_queue_status_unknown",
                format!("session queue received unknown queue health status: {other}"),
                &["request_queue"],
            ));
        }
    };
    let recommended_actions = session_queue_health_recommended_actions(state_dir, &health)?;
    let recommended_action_kinds = recommended_actions
        .iter()
        .filter_map(|action| action.get("action").and_then(Value::as_str))
        .map(ToOwned::to_owned)
        .collect::<Vec<_>>();
    let pending_requests = count_files_with_extension(&session_requests_dir(state_dir), "json")?;
    let running_requests = count_files_with_extension(&session_running_dir(state_dir), "json")?;
    let pending_responses = count_files_with_extension(&session_responses_dir(state_dir), "json")?;

    Ok(json!({
        "schema_version": "session.queue.v0.1",
        "state_dir": state_dir.display().to_string(),
        "generated_at_unix_ms": now_ms,
        "status": status,
        "counts": {
            "pending_requests": pending_requests,
            "running_requests": running_requests,
            "pending_responses": pending_responses
        },
        "admission": {
            "can_enqueue": can_enqueue,
            "status": if can_enqueue { "ready" } else { "blocked" },
            "blocked_code": if can_enqueue { Value::Null } else { json!("request_queue_needs_attention") },
            "preflight_command": "session command-check <command...>",
            "message": if can_enqueue {
                "daemon request queue can accept another request"
            } else {
                "daemon request queue needs attention before enqueueing another request"
            }
        },
        "health": health,
        "previews": {
            "preview_limit": SESSION_PENDING_REQUEST_PREVIEW_LIMIT,
            "pending_requests": session_pending_request_preview(
                state_dir,
                SESSION_PENDING_REQUEST_PREVIEW_LIMIT
            )?,
            "running_requests": session_running_request_preview(
                state_dir,
                SESSION_PENDING_REQUEST_PREVIEW_LIMIT
            )?,
            "pending_responses": session_pending_response_preview(
                state_dir,
                SESSION_PENDING_REQUEST_PREVIEW_LIMIT
            )?
        },
        "recommended_action_kinds": recommended_action_kinds,
        "recommended_actions": recommended_actions,
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true
        }
    }))
}

fn session_readiness_payload(
    global: &GlobalOptions,
    flags: &FlagArgs,
    state_dir: &Path,
    config: Option<&UserConfig>,
    command_name: &str,
) -> CliOutcome<Value> {
    flags.expect_positionals(command_name, 0)?;
    let status_view = session_status_payload_with_config(state_dir, true, config)?;
    let can_accept_requests = status_view
        .pointer("/diagnostics/liveness/can_accept_requests")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let liveness_status = status_view
        .pointer("/diagnostics/liveness/status")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let endpoint = parse_optional_string_value(flags, "--endpoint")?;
    let transport = endpoint.as_deref().map(session_readiness_transport_check);
    let transport_safe = transport
        .as_ref()
        .and_then(|value| value.get("safe_to_connect"))
        .and_then(Value::as_bool)
        .unwrap_or(true);
    let recommended_actions = status_view
        .pointer("/diagnostics/recommended_actions")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let queue_summary = session_readiness_queue_summary(&status_view)?;
    let instance_summary = session_readiness_instance_summary(&status_view, global)?;
    let action_kinds = recommended_actions
        .iter()
        .filter_map(|action| action.get("action").and_then(Value::as_str))
        .map(ToOwned::to_owned)
        .collect::<Vec<_>>();
    let blockers = session_readiness_blockers(
        global,
        can_accept_requests,
        liveness_status,
        transport.as_ref(),
        &instance_summary,
    );
    let instance_ready = session_readiness_instance_ready(&instance_summary);
    let ready = can_accept_requests && transport_safe && instance_ready;
    let status = if ready && recommended_actions.is_empty() {
        "ready"
    } else if ready {
        "degraded"
    } else {
        "not_ready"
    };
    Ok(json!({
        "schema_version": "session.readiness.v0.1",
        "state_dir": state_dir.display().to_string(),
        "scope": {
            "instance": global.instance.clone(),
            "game": global.game.clone(),
            "server": global.server.clone()
        },
        "ready": ready,
        "status": status,
        "daemon": {
            "status": liveness_status,
            "can_accept_requests": can_accept_requests,
            "running": status_view.get("running").and_then(Value::as_bool).unwrap_or(false)
        },
        "queues": queue_summary,
        "instances": instance_summary,
        "transport": transport.unwrap_or_else(|| json!({
            "checked": false,
            "safe_to_connect": null,
            "check_command": "session transport check --endpoint <url>",
            "daemon_check_command": "session request transport check --endpoint <url>"
        })),
        "stream_preflight": {
            "status": "available",
            "check_command": "stream check",
            "daemon_check_command": "session request stream check",
            "schema_version": "session.stream_check.v0.1",
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "requires_separate_instance_and_lease_check": true
        },
        "policy_summary": session_readiness_policy_summary(),
        "recommended_action_kinds": action_kinds,
        "recommended_actions": recommended_actions,
        "blockers": blockers,
        "status_view": status_view
    }))
}

fn session_connect_plan_payload(
    global: &GlobalOptions,
    flags: &FlagArgs,
    state_dir: &Path,
    config: Option<&UserConfig>,
    command_name: &str,
) -> CliOutcome<Value> {
    flags.expect_positionals(command_name, 0)?;
    let readiness = session_readiness_payload(global, flags, state_dir, config, command_name)?;
    let stream_preflight = run_stream_check(global, flags)?;
    let readiness_ready = readiness
        .get("ready")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let stream_safe = stream_preflight
        .get("safe_to_start")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let transport_safe = readiness
        .pointer("/transport/safe_to_connect")
        .and_then(Value::as_bool)
        .unwrap_or(true);
    let blockers = session_connect_plan_blockers(&readiness, &stream_preflight);
    let safe_to_start_client = readiness_ready && stream_safe && transport_safe;
    let next_actions = session_connect_plan_next_actions(
        &readiness,
        &stream_preflight,
        readiness_ready,
        stream_safe,
        transport_safe,
        safe_to_start_client,
    );
    Ok(json!({
        "schema_version": "session.connect_plan.v0.1",
        "status": if safe_to_start_client { "ready" } else { "blocked" },
        "safe_to_start_client": safe_to_start_client,
        "safe_to_start_stream": stream_safe,
        "safe_to_connect_transport": transport_safe,
        "mode": "client_connect_preflight",
        "client_surfaces": {
            "local_cli": {
                "available": true,
                "encryption_required": false,
                "authentication_required": false
            },
            "daemon_file_ipc": {
                "available_when_daemon_alive": true,
                "serialized_by_daemon": true
            },
            "bounded_stream": {
                "preflight_schema_version": "session.stream_check.v0.1",
                "safe_to_start": stream_safe,
                "input_relay_requires_matching_lease": true
            },
            "trusted_remote": {
                "status": "reserved",
                "requires_encryption": true,
                "requires_authentication": true,
                "safe_to_connect_transport": transport_safe
            }
        },
        "readiness": readiness,
        "transport": readiness.get("transport").cloned().unwrap_or(Value::Null),
        "stream_preflight": stream_preflight,
        "blockers": blockers,
        "next_actions": next_actions,
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "does_not_start_apps": true,
            "does_not_read_resource_repositories": true
        }
    }))
}

fn session_connect_plan_next_actions(
    readiness: &Value,
    stream_preflight: &Value,
    readiness_ready: bool,
    stream_safe: bool,
    transport_safe: bool,
    safe_to_start_client: bool,
) -> Value {
    let mut ordered = Vec::new();
    if !readiness_ready {
        ordered.push(session_connect_plan_next_action(
            1,
            "resolve_readiness_blockers",
            "Inspect readiness, queue, lease, instance, and daemon liveness before opening a client.",
            "session readiness",
            true,
        ));
    }
    if !transport_safe {
        ordered.push(session_connect_plan_next_action(
            2,
            "review_trusted_transport_policy",
            "Fix trusted remote transport policy before any remote UI/API channel is considered.",
            "session transport check --endpoint <url>",
            true,
        ));
    }
    if !stream_safe {
        ordered.push(session_connect_plan_next_action(
            3,
            "inspect_stream_preflight",
            "Inspect stream and input-relay preflight before any interactive stream work.",
            "stream check",
            true,
        ));
    }
    ordered.push(session_connect_plan_next_action(
        4,
        "review_phase_c_plan",
        "Review self-heal, interaction-flow, trusted-channel, and live-validation boundaries before implementing Phase C execution.",
        "session phase-c-plan [--endpoint <url>] [--trigger <kind>] [--to <page>]",
        true,
    ));
    if safe_to_start_client {
        ordered.push(session_connect_plan_next_action(
            5,
            "open_bounded_local_stream_if_needed",
            "A bounded local stream can be opened by a separate command if the client needs frame events.",
            "stream --max-frames <N>",
            false,
        ));
    }
    json!({
        "schema_version": "session.connect_next_actions.v0.1",
        "status": if safe_to_start_client { "ready" } else { "blocked" },
        "ordered": ordered,
        "readiness": {
            "ready": readiness_ready,
            "status": readiness.get("status").cloned().unwrap_or(Value::Null),
            "recommended_action_kinds": readiness
                .get("recommended_action_kinds")
                .cloned()
                .unwrap_or_else(|| json!([]))
        },
        "stream": {
            "safe_to_start": stream_safe,
            "input_relay_requested": stream_preflight
                .pointer("/input_relay/requested")
                .cloned()
                .unwrap_or(Value::Null),
            "input_relay_requires_matching_lease": true
        },
        "trusted_channel": {
            "transport_safe": transport_safe,
            "remote_status": "reserved",
            "requires_security_review": true,
            "does_not_start_listener": true,
            "does_not_issue_tokens": true,
            "does_not_start_tls": true
        },
        "live_validation": {
            "status": "deferred",
            "deferred_code": "requires-live-device",
            "must_not_mark_live_pass_from_offline_checks": true
        },
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "does_not_issue_tokens": true,
            "does_not_start_tls": true,
            "does_not_mark_live_validation_passed": true
        }
    })
}

fn session_connect_plan_next_action(
    priority: u8,
    action: &str,
    reason: &str,
    command: &str,
    read_only: bool,
) -> Value {
    json!({
        "priority": priority,
        "action": action,
        "reason": reason,
        "command": command,
        "read_only": read_only
    })
}

fn session_stream_plan_payload(
    global: &GlobalOptions,
    flags: &FlagArgs,
    state_dir: &Path,
    config: Option<&UserConfig>,
    command_name: &str,
) -> CliOutcome<Value> {
    flags.expect_positionals(command_name, 0)?;
    let connect_plan =
        session_connect_plan_payload(global, flags, state_dir, config, command_name)?;
    let stream_preflight = connect_plan
        .get("stream_preflight")
        .cloned()
        .unwrap_or(Value::Null);
    let safe_to_start_client = connect_plan
        .get("safe_to_start_client")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let safe_to_start_stream = connect_plan
        .get("safe_to_start_stream")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let safe_to_connect_transport = connect_plan
        .get("safe_to_connect_transport")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let input_relay_requested = stream_preflight
        .pointer("/input_relay/requested")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let input_relay_action_count = stream_preflight
        .pointer("/input_relay/action_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let safe_to_open_stream =
        safe_to_start_client && safe_to_start_stream && safe_to_connect_transport;
    let blockers = session_stream_plan_blockers(&connect_plan);
    let transport = connect_plan
        .get("transport")
        .cloned()
        .unwrap_or(Value::Null);
    let next_actions = session_stream_plan_next_actions(SessionStreamPlanNextActionInputs {
        connect_plan: &connect_plan,
        stream_preflight: &stream_preflight,
        transport: &transport,
        safe_to_start_client,
        safe_to_start_stream,
        safe_to_connect_transport,
        safe_to_open_stream,
        input_relay_requested,
        input_relay_action_count,
    });

    Ok(json!({
        "schema_version": "session.stream_plan.v0.1",
        "status": if safe_to_open_stream { "ready" } else { "blocked" },
        "mode": "interactive_stream_preflight",
        "safe_to_open_stream": safe_to_open_stream,
        "safe_to_start_client": safe_to_start_client,
        "safe_to_start_stream": safe_to_start_stream,
        "safe_to_connect_transport": safe_to_connect_transport,
        "input_relay_requested": input_relay_requested,
        "input_relay_action_count": input_relay_action_count,
        "stream_modes": {
            "bounded_local_cli": {
                "status": "available",
                "command": "stream --max-frames <N>",
                "long_lived": false,
                "encryption_required": false
            },
            "daemon_request": {
                "status": if safe_to_start_client { "available" } else { "blocked" },
                "command": "session request stream",
                "check_command": "session request stream check",
                "serialized_by_daemon": true,
                "input_relay_requires_matching_lease": true
            },
            "trusted_remote_long_lived": {
                "status": "reserved",
                "implemented": false,
                "requires_encryption": true,
                "requires_authentication": true,
                "token_configured": env::var_os(TRUSTED_REMOTE_TOKEN_ENV).is_some(),
                "client_certificate_configured": env::var_os(TRUSTED_REMOTE_CLIENT_CERT_ENV).is_some(),
                "preflight_command": "session transport check --endpoint <url>"
            }
        },
        "connect_plan": connect_plan,
        "stream_preflight": stream_preflight,
        "transport": transport,
        "blockers": blockers,
        "next_actions": next_actions,
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "does_not_start_apps": true,
            "does_not_read_resource_repositories": true
        }
    }))
}

struct SessionStreamPlanNextActionInputs<'a> {
    connect_plan: &'a Value,
    stream_preflight: &'a Value,
    transport: &'a Value,
    safe_to_start_client: bool,
    safe_to_start_stream: bool,
    safe_to_connect_transport: bool,
    safe_to_open_stream: bool,
    input_relay_requested: bool,
    input_relay_action_count: u64,
}

fn session_stream_plan_next_actions(input: SessionStreamPlanNextActionInputs<'_>) -> Value {
    let mut ordered = Vec::new();
    if !input.safe_to_start_client {
        ordered.push(session_connect_plan_next_action(
            1,
            "resolve_connect_plan_blockers",
            "Inspect readiness, daemon liveness, queue health, lease state, and transport policy before opening an interactive stream.",
            "session connect-plan [--endpoint <url>] [stream check flags]",
            true,
        ));
    }
    if !input.safe_to_start_stream {
        ordered.push(session_connect_plan_next_action(
            2,
            "inspect_stream_preflight",
            "Inspect bounded stream and input-relay preflight before any UI interaction flow work.",
            "stream check",
            true,
        ));
    }
    if input.input_relay_requested && !input.safe_to_open_stream {
        ordered.push(session_connect_plan_next_action(
            3,
            "resolve_input_relay_lease",
            "Input relay is requested but the stream is not safe to open; inspect the Session Layer lease before relaying clicks or keys.",
            "session lease status",
            true,
        ));
    }
    ordered.push(session_connect_plan_next_action(
        4,
        "review_trusted_remote_stream_boundary",
        "Review the trusted remote transport plan before any long-lived stream, listener, token, or TLS work.",
        "session transport plan [--endpoint <url>]",
        true,
    ));
    ordered.push(session_connect_plan_next_action(
        5,
        "review_phase_c_plan",
        "Review Phase C self-heal, interaction-flow, trusted-channel, and live-validation boundaries before enabling execution.",
        "session phase-c-plan [--endpoint <url>] [--trigger <kind>] [--to <page>]",
        true,
    ));
    if input.safe_to_open_stream {
        ordered.push(session_connect_plan_next_action(
            6,
            "open_bounded_local_stream",
            "A bounded local stream can be opened by a separate command after preflight passes.",
            "stream --max-frames <N>",
            false,
        ));
    }

    json!({
        "schema_version": "session.stream_next_actions.v0.1",
        "status": if input.safe_to_open_stream { "ready" } else { "blocked" },
        "ordered": ordered,
        "connect": {
            "safe_to_start_client": input.safe_to_start_client,
            "safe_to_connect_transport": input.safe_to_connect_transport,
            "status": input.connect_plan.get("status").cloned().unwrap_or(Value::Null),
            "first_connect_action": input.connect_plan
                .pointer("/next_actions/ordered/0/action")
                .cloned()
                .unwrap_or(Value::Null)
        },
        "stream": {
            "safe_to_start_stream": input.safe_to_start_stream,
            "safe_to_open_stream": input.safe_to_open_stream,
            "input_relay_requested": input.input_relay_requested,
            "input_relay_action_count": input.input_relay_action_count,
            "input_relay_requires_matching_lease": true,
            "lease_gate": input.stream_preflight
                .pointer("/input_relay/lease_gate")
                .cloned()
                .unwrap_or(Value::Null)
        },
        "phase_c": {
            "self_heal_plan_command": "session self-heal-plan [--trigger <kind>] [--to <page>]",
            "interaction_flow_plan_command": "session stream-plan [--endpoint <url>]",
            "trusted_channel_plan_command": "session transport plan [--endpoint <url>]",
            "live_validation_status": "deferred",
            "deferred_code": "requires-live-device"
        },
        "trusted_channel": {
            "transport_safe": input.safe_to_connect_transport,
            "remote_status": "reserved",
            "requires_encryption": true,
            "requires_authentication": true,
            "transport_endpoint": input.transport.get("endpoint").cloned().unwrap_or(Value::Null),
            "does_not_start_listener": true,
            "does_not_issue_tokens": true,
            "does_not_start_tls": true
        },
        "live_validation": {
            "status": "deferred",
            "deferred_code": "requires-live-device",
            "must_not_mark_live_pass_from_offline_checks": true
        },
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "does_not_issue_tokens": true,
            "does_not_start_tls": true,
            "does_not_mark_live_validation_passed": true
        }
    })
}

fn session_connect_plan_blockers(readiness: &Value, stream_preflight: &Value) -> Vec<Value> {
    let mut blockers = readiness
        .get("blockers")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    if !stream_preflight
        .get("safe_to_start")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        blockers.push(json!({
            "kind": "stream_preflight",
            "schema_version": stream_preflight.get("schema_version"),
            "input_relay_requested": stream_preflight.pointer("/input_relay/requested"),
            "lease_gate": stream_preflight.pointer("/input_relay/lease_gate"),
            "routing": stream_preflight.get("routing"),
            "message": "Stream preflight is not safe to start"
        }));
    }
    blockers
}

fn session_stream_plan_blockers(connect_plan: &Value) -> Vec<Value> {
    connect_plan
        .get("blockers")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
}

