fn session_readiness_instance_summary(
    status_view: &Value,
    global: &GlobalOptions,
) -> CliOutcome<Value> {
    let instances = status_view
        .pointer("/diagnostics/instances")
        .ok_or_else(|| {
            CliError::new(
                ErrorKind::RuntimeNotRunning,
                "readiness_status_view_missing_field",
                "session readiness could not find diagnostics.instances in status view",
                &["session_status", "readiness"],
            )
        })?;
    let available = instances
        .get("available")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let count = instances.get("count").and_then(Value::as_u64).unwrap_or(0);
    let entries = instances
        .get("instances")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let selected_instance = global.instance.as_deref().and_then(|selected| {
        entries
            .iter()
            .find(|entry| entry.get("id").and_then(Value::as_str) == Some(selected))
            .cloned()
    });
    let selected_missing_required = selected_instance
        .as_ref()
        .and_then(readiness_instance_missing_required_fields);
    let selected_status = match (global.instance.as_deref(), selected_instance.as_ref()) {
        (None, _) => "not_selected",
        (Some(_), _) if !available => "registry_unavailable",
        (Some(_), None) => "not_found",
        (Some(_), Some(_)) if selected_missing_required.is_some() => "needs_configuration",
        (Some(_), Some(_)) => "ready",
    };
    let missing_required = entries
        .iter()
        .filter_map(readiness_instance_missing_required_fields)
        .collect::<Vec<_>>();
    let status = if !available {
        "unavailable"
    } else if count == 0 {
        "empty"
    } else if missing_required.is_empty() {
        "ready"
    } else {
        "needs_configuration"
    };
    Ok(json!({
        "schema_version": "session.readiness_instances.v0.1",
        "available": available,
        "count": count,
        "status": status,
        "selected_status": selected_status,
        "selected_instance": selected_instance,
        "selected_missing_required": selected_missing_required,
        "missing_required": missing_required,
        "instances": entries
    }))
}

fn readiness_instance_missing_required_fields(entry: &Value) -> Option<Value> {
    let fields = [
        ("serial_configured", "serial"),
        ("game_configured", "game"),
        ("server_configured", "server"),
    ]
    .into_iter()
    .filter_map(|(configured_field, field)| {
        if entry
            .get(configured_field)
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            None
        } else {
            Some(field)
        }
    })
    .collect::<Vec<_>>();
    if fields.is_empty() {
        None
    } else {
        Some(json!({
            "id": entry.get("id").cloned().unwrap_or(Value::Null),
            "fields": fields
        }))
    }
}

fn session_readiness_queue_summary(status_view: &Value) -> CliOutcome<Value> {
    let queues = status_view.pointer("/diagnostics/queues").ok_or_else(|| {
        CliError::new(
            ErrorKind::RuntimeNotRunning,
            "readiness_status_view_missing_field",
            "session readiness could not find diagnostics.queues in status view",
            &["session_status", "readiness"],
        )
    })?;
    let health = session_readiness_required_queue_field(queues, "health")?;
    Ok(json!({
        "schema_version": "session.readiness_queues.v0.1",
        "status": health.get("status").cloned().unwrap_or(Value::Null),
        "pending_requests": session_readiness_required_queue_field(queues, "pending_requests")?,
        "running_requests": session_readiness_required_queue_field(queues, "running_requests")?,
        "pending_responses": session_readiness_required_queue_field(queues, "pending_responses")?,
        "health": health
    }))
}

fn session_readiness_required_queue_field(queues: &Value, field: &str) -> CliOutcome<Value> {
    queues.get(field).cloned().ok_or_else(|| {
        CliError::new(
            ErrorKind::RuntimeNotRunning,
            "readiness_status_view_missing_field",
            format!("session readiness could not find diagnostics.queues.{field} in status view"),
            &["session_status", "readiness"],
        )
    })
}

fn session_readiness_transport_check(endpoint: &str) -> Value {
    let check = runtime_endpoint_check(endpoint);
    json!({
        "checked": true,
        "endpoint": endpoint,
        "check": check,
        "safe_to_connect": check.get("ok").and_then(Value::as_bool).unwrap_or(false)
    })
}

fn session_readiness_blockers(
    global: &GlobalOptions,
    can_accept_requests: bool,
    liveness_status: &str,
    transport: Option<&Value>,
    instance_summary: &Value,
) -> Vec<Value> {
    let mut blockers = Vec::new();
    if !can_accept_requests {
        blockers.push(json!({
            "kind": "daemon_liveness",
            "status": liveness_status,
            "message": "Session daemon is not accepting requests"
        }));
    }
    if let Some(transport) = transport {
        if transport
            .get("safe_to_connect")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            return blockers;
        }
        blockers.push(json!({
            "kind": "transport",
            "endpoint": transport.get("endpoint"),
            "error_code": transport.pointer("/check/error_code"),
            "blocked_by": transport.pointer("/check/blocked_by"),
            "message": "Transport endpoint is not safe to connect"
        }));
    }
    if let Some(blocker) = session_readiness_instance_blocker(global, instance_summary) {
        blockers.push(blocker);
    }
    blockers
}

fn session_readiness_instance_ready(instance_summary: &Value) -> bool {
    matches!(
        instance_summary
            .get("selected_status")
            .and_then(Value::as_str),
        Some("not_selected" | "ready")
    )
}

fn session_readiness_instance_blocker(
    global: &GlobalOptions,
    instance_summary: &Value,
) -> Option<Value> {
    let selected = global.instance.as_ref()?;
    match instance_summary
        .get("selected_status")
        .and_then(Value::as_str)
    {
        Some("ready" | "not_selected") => None,
        Some("needs_configuration") => Some(json!({
            "kind": "instance_configuration",
            "instance": selected,
            "missing_required": instance_summary.get("selected_missing_required"),
            "message": "Selected instance is missing required configuration"
        })),
        Some("not_found") => Some(json!({
            "kind": "instance_not_found",
            "instance": selected,
            "available_instances": instance_summary.get("count"),
            "message": "Selected instance is not present in the instance registry"
        })),
        Some("registry_unavailable") => Some(json!({
            "kind": "instance_registry",
            "instance": selected,
            "message": "Instance registry is unavailable"
        })),
        Some(status) => Some(json!({
            "kind": "instance_configuration",
            "instance": selected,
            "status": status,
            "message": "Selected instance readiness status is not usable"
        })),
        None => Some(json!({
            "kind": "instance_configuration",
            "instance": selected,
            "message": "Selected instance readiness status is missing"
        })),
    }
}

#[derive(Debug, Clone, Copy)]
struct SessionCommandCheckClass {
    command_class: &'static str,
    requires_lease: bool,
    device_affecting: bool,
}

fn run_session_command_check(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    let state_dir = session_state_dir_from_flags(&flags)?;
    let config = read_user_config()?;
    session_command_check_payload(
        global,
        &flags,
        &state_dir,
        Some(&config),
        "session command-check",
    )
}

fn run_session_submit_plan(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    let state_dir = session_state_dir_from_flags(&flags)?;
    let config = read_user_config()?;
    session_submit_plan_payload(
        global,
        &flags,
        &state_dir,
        Some(&config),
        "session submit-plan",
    )
}

fn run_session_validation_plan(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "validation_plan", args);
    }
    session_validation_plan_payload(global, &flags, "session validation-plan")
}

