fn session_submit_plan_blockers(
    readiness: &Value,
    command_check: &Value,
    queue: &Value,
) -> Vec<Value> {
    let mut blockers = Vec::new();
    extend_blockers(&mut blockers, readiness.get("blockers"));
    extend_blockers(&mut blockers, command_check.get("blockers"));
    if !queue
        .pointer("/admission/can_enqueue")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        blockers.push(json!({
            "kind": "queue_admission",
            "code": queue.pointer("/admission/blocked_code"),
            "message": queue.pointer("/admission/message"),
            "queue": queue
        }));
    }
    blockers
}

fn extend_blockers(blockers: &mut Vec<Value>, value: Option<&Value>) {
    if let Some(items) = value.and_then(Value::as_array) {
        blockers.extend(items.iter().cloned());
    }
}

fn session_command_check_tokens(flags: &FlagArgs, command_name: &str) -> CliOutcome<Vec<String>> {
    if flags.positionals.is_empty() {
        return Err(CliError::usage(format!(
            "{command_name} requires <command...>"
        )));
    }
    let mut tokens = flags.positionals.clone();
    if tokens.first().map(String::as_str) == Some("session") {
        tokens.remove(0);
    }
    if tokens.is_empty() {
        return Err(CliError::usage(format!(
            "{command_name} requires <command...>"
        )));
    }
    Ok(tokens)
}

fn classify_session_command_for_check(
    tokens: &[String],
    flags: &FlagArgs,
) -> CliOutcome<SessionCommandCheckClass> {
    let first = tokens.first().map(String::as_str).unwrap_or_default();
    let second = tokens.get(1).map(String::as_str);
    let read_only = SessionCommandCheckClass {
        command_class: "read_only",
        requires_lease: false,
        device_affecting: false,
    };
    let device_read_only = SessionCommandCheckClass {
        command_class: "read_only",
        requires_lease: false,
        device_affecting: true,
    };
    let control = SessionCommandCheckClass {
        command_class: "control",
        requires_lease: true,
        device_affecting: true,
    };
    let daemon_state = SessionCommandCheckClass {
        command_class: "daemon_state",
        requires_lease: false,
        device_affecting: false,
    };
    let lease_arbitration = SessionCommandCheckClass {
        command_class: "lease_arbitration",
        requires_lease: false,
        device_affecting: false,
    };

    match first {
        "status" | "readiness" | "connect-plan" | "stream-plan" | "queue" | "journal"
        | "events" | "response" | "request-state" | "contract" | "api" | "transport"
        | "capabilities" | "bootstrap" | "command-check" | "submit-plan" | "validation-plan"
        | "throat-policy" | "capture-policy" | "self-heal-policy" | "self-heal-plan"
        | "phase-c-plan" => Ok(read_only),
        "devices" | "capture" | "capture-diagnose" | "recognize" | "detect-page"
        | "current-page" | "is-visible" | "locate" | "monitor-once" => Ok(device_read_only),
        "stream" => {
            if second == Some("check") || !stream_input_relay_requested(flags) {
                Ok(device_read_only)
            } else {
                Ok(control)
            }
        }
        "monitor" => {
            if flags.bool("--recover") {
                Ok(control)
            } else {
                Ok(device_read_only)
            }
        }
        "recover" => {
            if flags.bool("--stale-capture") {
                Ok(device_read_only)
            } else {
                Ok(control)
            }
        }
        "instance" => match second {
            Some("app" | "connect" | "reconnect") => Ok(control),
            Some("list" | "registry" | "health" | "keep-alive") | None => Ok(device_read_only),
            Some(other) => Err(CliError::usage(format!(
                "unsupported session command-check instance command: {other}"
            ))),
        },
        "app" | "lab-run" | "package-run" | "operation-run" | "tap" | "swipe" | "long-tap"
        | "key" | "text" | "tap-target" | "navigate" => Ok(control),
        "lab" if second == Some("run") => Ok(control),
        "package" if second == Some("run") => Ok(control),
        "operation" if matches!(second, Some("run" | "dry-run")) => Ok(control),
        "lease" => Ok(lease_arbitration),
        "record" | "monitor-policy" => Ok(daemon_state),
        other => Err(CliError::usage(format!(
            "unsupported session command-check command: {other}"
        ))),
    }
}

fn session_command_check_lease_gate(
    state_dir: &Path,
    global: &GlobalOptions,
    flags: &FlagArgs,
    requires_lease: bool,
) -> CliOutcome<Value> {
    let session_global = SessionCommandGlobal::from_global(global);
    let instance_id = session_command_instance_id(&session_global);
    let lease_path = session_lease_path(state_dir, &instance_id);
    if !requires_lease {
        return Ok(json!({
            "ok": true,
            "required": false,
            "status": "not_required",
            "instance": instance_id,
            "lease_path": lease_path.display().to_string()
        }));
    }
    let requested = session_command_lease_from_flags(flags);
    let Some(requested) = requested.as_ref().filter(|lease| !lease.holder.is_empty()) else {
        return Ok(json!({
            "ok": false,
            "required": true,
            "status": "blocked",
            "code": "lab_lease_required",
            "message": "control command requires --lease-holder <id>",
            "instance": instance_id,
            "lease_path": lease_path.display().to_string()
        }));
    };
    let Some(current) = read_json_file::<SessionLease>(&lease_path)? else {
        return Ok(json!({
            "ok": false,
            "required": true,
            "status": "blocked",
            "code": "lab_lease_missing",
            "message": format!("control command requires an active lease for {instance_id}"),
            "requested_lease": requested,
            "instance": instance_id,
            "lease_path": lease_path.display().to_string()
        }));
    };
    match validate_lease_request(&current, requested) {
        Ok(()) => Ok(json!({
            "ok": true,
            "required": true,
            "status": "ready",
            "requested_lease": requested,
            "current_lease": current,
            "instance": instance_id,
            "lease_path": lease_path.display().to_string()
        })),
        Err(err) => Ok(json!({
            "ok": false,
            "required": true,
            "status": "blocked",
            "code": err.code,
            "message": err.message,
            "blocked_by": err.blocked_by,
            "requested_lease": requested,
            "current_lease": current,
            "instance": instance_id,
            "lease_path": lease_path.display().to_string()
        })),
    }
}

fn session_command_check_queue_gate(state_dir: &Path, check_queue: bool) -> CliOutcome<Value> {
    if !check_queue {
        return Ok(json!({
            "ok": true,
            "checked": false,
            "status": "not_checked",
            "message": "target command does not require daemon queue admission"
        }));
    }
    let health = session_queue_health(
        state_dir,
        current_unix_ms(),
        SESSION_DAEMON_REQUEST_TIMEOUT_MS,
    )?;
    let Some(status) = health.get("status").and_then(Value::as_str) else {
        return Err(CliError::new(
            ErrorKind::RuntimeNotRunning,
            "command_check_queue_status_missing",
            "session command-check could not read queue health status",
            &["request_queue", "command_check"],
        ));
    };
    match status {
        "clear" | "active" => Ok(json!({
            "ok": true,
            "checked": true,
            "status": status,
            "health": health
        })),
        "needs_attention" => Ok(json!({
            "ok": false,
            "checked": true,
            "status": status,
            "code": "request_queue_needs_attention",
            "message": "daemon request queue needs attention before submitting another request",
            "health": health
        })),
        other => Err(CliError::new(
            ErrorKind::RuntimeNotRunning,
            "command_check_queue_status_unknown",
            format!("session command-check received unknown queue health status: {other}"),
            &["request_queue", "command_check"],
        )),
    }
}

fn session_command_check_instance_gate(
    global: &GlobalOptions,
    classification: SessionCommandCheckClass,
    config: Option<&UserConfig>,
) -> Value {
    let Some(selected) = global.instance.as_deref() else {
        return json!({
            "ok": true,
            "required": false,
            "status": "not_selected",
            "message": "no selected instance was provided for this preflight"
        });
    };
    if !classification.device_affecting {
        return json!({
            "ok": true,
            "required": false,
            "status": "not_required",
            "instance": selected,
            "message": "target command does not touch a device or emulator instance"
        });
    }
    let Some(config) = config else {
        return json!({
            "ok": false,
            "required": true,
            "status": "blocked",
            "code": "instance_registry_unavailable",
            "instance": selected,
            "message": "selected instance cannot be checked because the instance registry is unavailable"
        });
    };
    let Some(instance) = config.instances.get(selected) else {
        return json!({
            "ok": false,
            "required": true,
            "status": "blocked",
            "code": "instance_not_found",
            "instance": selected,
            "message": "selected instance is not present in the instance registry"
        });
    };
    let missing = instance_missing_required_fields(instance);
    if !missing.is_empty() {
        return json!({
            "ok": false,
            "required": true,
            "status": "blocked",
            "code": "instance_configuration",
            "instance": selected,
            "missing_required": missing,
            "message": "selected instance is missing required serial, game, or server configuration"
        });
    }
    json!({
        "ok": true,
        "required": true,
        "status": "ready",
        "instance": selected,
        "game": instance.game,
        "server": instance.server,
        "serial_configured": instance.serial.is_some()
    })
}

fn session_command_check_blockers(
    daemon_route_ok: bool,
    daemon_alive: bool,
    strict_session_required: bool,
    lease_gate: &Value,
    queue_gate: &Value,
    instance_gate: &Value,
) -> Vec<Value> {
    let mut blockers = Vec::new();
    if !daemon_route_ok {
        blockers.push(json!({
            "kind": "daemon_liveness",
            "daemon_alive": daemon_alive,
            "strict_session_required": strict_session_required,
            "message": "command requires an alive Session daemon before submission"
        }));
    }
    if !lease_gate
        .get("ok")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        blockers.push(json!({
            "kind": "lease_gate",
            "code": lease_gate.get("code"),
            "message": lease_gate.get("message"),
            "lease_gate": lease_gate
        }));
    }
    if !queue_gate
        .get("ok")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        blockers.push(json!({
            "kind": "queue_gate",
            "code": queue_gate.get("code"),
            "message": queue_gate.get("message"),
            "queue_gate": queue_gate
        }));
    }
    if !instance_gate
        .get("ok")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        blockers.push(json!({
            "kind": "instance_gate",
            "code": instance_gate.get("code"),
            "message": instance_gate.get("message"),
            "instance_gate": instance_gate
        }));
    }
    blockers
}

fn run_session_transport(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "transport", args);
    }
    session_transport_payload(&flags)
}

fn session_transport_payload(flags: &FlagArgs) -> CliOutcome<Value> {
    match flags.positionals.first().map(String::as_str) {
        None => Ok(session_transport_contract()),
        Some("plan") => session_transport_plan_payload(&flags.without_first_positional()),
        Some("check") => session_transport_check_payload(&flags.without_first_positional()),
        Some(other) => Err(CliError::usage(format!(
            "unknown session transport command: {other}"
        ))),
    }
}

fn session_transport_plan_payload(flags: &FlagArgs) -> CliOutcome<Value> {
    flags.expect_positionals("session transport plan", 0)?;
    let endpoint = parse_optional_string_value(flags, "--endpoint")?;
    let endpoint_policy = session_transport_plan_endpoint_policy(endpoint.as_deref());
    let endpoint_policy_safe = endpoint_policy
        .get("safe_for_policy")
        .and_then(Value::as_bool);
    let has_endpoint_policy_blocker = endpoint_policy_safe == Some(false);
    let blockers = session_transport_plan_blockers(&endpoint_policy);
    let next_actions = session_transport_plan_next_actions(&endpoint_policy, &blockers);
    Ok(json!({
        "schema_version": "session.transport_plan.v0.1",
        "status": if has_endpoint_policy_blocker { "blocked" } else { "reserved" },
        "mode": "trusted_channel_startup_preflight",
        "local_cli": {
            "status": "available",
            "command": "actinglab",
            "encryption_required": false,
            "authentication_required": false
        },
        "daemon_file_ipc": {
            "status": "available",
            "command": "session request <command>",
            "serialized_by_daemon": true,
            "control_requests_require_matching_lease": true
        },
        "trusted_remote": {
            "status": "reserved",
            "network_listener_implemented": false,
            "safe_to_start_listener": false,
            "ready_to_accept_remote_clients": false,
            "requires_encryption": true,
            "requires_authentication": true,
            "token_configured": env_var_non_empty(TRUSTED_REMOTE_TOKEN_ENV),
            "client_certificate_configured": env_var_non_empty(TRUSTED_REMOTE_CLIENT_CERT_ENV),
            "token_env": TRUSTED_REMOTE_TOKEN_ENV,
            "client_certificate_env": TRUSTED_REMOTE_CLIENT_CERT_ENV,
            "endpoint_policy": endpoint_policy,
            "required_before_enable": [
                "reviewed network listener implementation",
                "TLS or mutually authenticated local IPC",
                "token or client certificate authentication",
                "request serialization through the resident Session Layer",
                "audit logging for accepted remote commands"
            ]
        },
        "blockers": blockers,
        "next_actions": next_actions,
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "does_not_probe_tcp": true,
            "does_not_issue_tokens": true,
            "does_not_start_tls": true,
            "does_not_read_resource_repositories": true
        }
    }))
}

fn session_transport_plan_endpoint_policy(endpoint: Option<&str>) -> Value {
    let Some(endpoint) = endpoint else {
        return json!({
            "checked": false,
            "safe_for_policy": null,
            "does_not_probe_tcp": true,
            "message": "No endpoint was provided; run with --endpoint <url> to classify local versus trusted remote policy."
        });
    };
    match runtime_endpoint_policy(endpoint) {
        Ok(policy) => json!({
            "checked": true,
            "endpoint": endpoint,
            "safe_for_policy": true,
            "policy": runtime_endpoint_policy_json(&policy),
            "does_not_probe_tcp": true
        }),
        Err(err) => json!({
            "checked": true,
            "endpoint": endpoint,
            "safe_for_policy": false,
            "error_code": err.code,
            "error": err.message,
            "blocked_by": err.blocked_by,
            "does_not_probe_tcp": true
        }),
    }
}

fn session_transport_plan_blockers(endpoint_policy: &Value) -> Vec<Value> {
    let mut blockers = vec![json!({
        "kind": "trusted_remote_listener",
        "code": "trusted_remote_listener_reserved",
        "message": "Trusted remote listener is reserved and is not implemented in this offline milestone."
    })];
    if endpoint_policy
        .get("safe_for_policy")
        .and_then(Value::as_bool)
        == Some(false)
    {
        blockers.push(json!({
            "kind": "trusted_remote_endpoint_policy",
            "code": endpoint_policy.get("error_code"),
            "message": endpoint_policy.get("error"),
            "blocked_by": endpoint_policy.get("blocked_by"),
            "endpoint": endpoint_policy.get("endpoint")
        }));
    }
    blockers
}

fn session_transport_plan_next_actions(endpoint_policy: &Value, blockers: &[Value]) -> Value {
    let endpoint_checked = endpoint_policy
        .get("checked")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let endpoint_safe = endpoint_policy
        .get("safe_for_policy")
        .and_then(Value::as_bool);
    let token_configured = env_var_non_empty(TRUSTED_REMOTE_TOKEN_ENV);
    let client_certificate_configured = env_var_non_empty(TRUSTED_REMOTE_CLIENT_CERT_ENV);
    let auth_material_configured = token_configured || client_certificate_configured;
    let mut ordered = Vec::new();
    let mut priority = 1;

    if !endpoint_checked {
        ordered.push(session_connect_plan_next_action(
            priority,
            "classify_endpoint_policy",
            "Classify the intended trusted remote endpoint before any listener or client transport work.",
            "session transport check --endpoint <url>",
            true,
        ));
        priority += 1;
    }

    if endpoint_safe == Some(false) {
        ordered.push(session_connect_plan_next_action(
            priority,
            "review_endpoint_policy_blocker",
            "Fix the trusted remote endpoint policy before any remote channel can be enabled.",
            "session transport check --endpoint <url>",
            true,
        ));
        priority += 1;
    }

    if !auth_material_configured {
        ordered.push(session_connect_plan_next_action(
            priority,
            "prepare_remote_auth_material",
            "Configure a token or client certificate before remote clients can authenticate.",
            "configure ACTINGLAB_TRUSTED_REMOTE_TOKEN or ACTINGLAB_TRUSTED_REMOTE_CLIENT_CERT",
            false,
        ));
        priority += 1;
    }

    ordered.push(session_connect_plan_next_action(
        priority,
        "review_listener_and_tls_design",
        "Review the network listener, TLS boundary, and authentication model before implementation.",
        "session transport plan [--endpoint <url>]",
        true,
    ));
    priority += 1;

    ordered.push(session_connect_plan_next_action(
        priority,
        "review_request_serialization_and_audit",
        "Remote commands must serialize through the resident Session Layer and leave an audit trail.",
        "session api",
        true,
    ));
    priority += 1;

    ordered.push(session_connect_plan_next_action(
        priority,
        "review_live_acceptance_checklist",
        "Trusted remote transport still requires live listener, TLS, auth, and operator validation later.",
        "session validation-plan",
        true,
    ));

    json!({
        "schema_version": "session.transport_next_actions.v0.1",
        "status": if endpoint_safe == Some(false) { "blocked" } else { "reserved" },
        "ordered": ordered,
        "trusted_remote": {
            "status": "reserved",
            "network_listener_implemented": false,
            "ready_to_accept_remote_clients": false,
            "endpoint_policy_checked": endpoint_checked,
            "endpoint_policy_safe": endpoint_safe,
            "endpoint": endpoint_policy.get("endpoint").cloned().unwrap_or(Value::Null),
            "token_configured": token_configured,
            "client_certificate_configured": client_certificate_configured,
            "auth_material_configured": auth_material_configured,
            "blocker_count": blockers.len()
        },
        "required_before_enable": [
            "reviewed network listener implementation",
            "TLS or mutually authenticated local IPC",
            "token or client certificate authentication",
            "request serialization through the resident Session Layer",
            "audit logging for accepted remote commands"
        ],
        "local_cli": {
            "status": "available",
            "encryption_required": false,
            "authentication_required": false
        },
        "daemon_file_ipc": {
            "status": "available",
            "serialized_by_daemon": true,
            "control_requests_require_matching_lease": true
        },
        "live_validation": {
            "status": "deferred",
            "deferred_code": "requires-live-device",
            "must_not_mark_live_pass_from_offline_checks": true
        },
        "guarantees": {
            "does_not_enqueue": true,
            "does_not_touch_device": true,
            "does_not_capture": true,
            "does_not_start_maatouch": true,
            "does_not_start_listener": true,
            "does_not_probe_tcp": true,
            "does_not_issue_tokens": true,
            "does_not_start_tls": true,
            "does_not_read_resource_repositories": true,
            "does_not_mark_live_validation_passed": true
        }
    })
}

fn session_transport_check_payload(flags: &FlagArgs) -> CliOutcome<Value> {
    flags.expect_positionals("session transport check", 0)?;
    let endpoint = flags.required("--endpoint")?;
    let check = runtime_endpoint_check(&endpoint);
    Ok(json!({
        "schema_version": "session.transport_check.v0.1",
        "endpoint": endpoint,
        "check": check,
        "safe_to_connect": check.get("ok").and_then(Value::as_bool).unwrap_or(false),
        "does_not_start_listener": true
    }))
}

fn run_session_events(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "events", args);
    }
    let state_dir = session_state_dir_from_flags(&flags)?;
    run_session_events_in_state_dir(
        global.instance.clone(),
        global.game.clone(),
        global.server.clone(),
        &flags,
        &state_dir,
    )
}

fn run_session_events_in_state_dir(
    instance: Option<String>,
    game: Option<String>,
    server: Option<String>,
    flags: &FlagArgs,
    state_dir: &Path,
) -> CliOutcome<Value> {
    match flags.positionals.first().map(String::as_str) {
        None => session_events_query_payload(state_dir, flags, instance, game, server),
        Some("wait") => run_session_events_wait(flags, state_dir, instance, game, server),
        Some(other) => Err(CliError::usage(format!(
            "unknown session events command: {other}"
        ))),
    }
}

fn session_events_query_payload(
    state_dir: &Path,
    flags: &FlagArgs,
    instance: Option<String>,
    game: Option<String>,
    server: Option<String>,
) -> CliOutcome<Value> {
    flags.expect_positionals("session events", 0)?;
    let limit = parse_optional_usize(flags, "--limit", 20)?;
    let after_unix_ms = parse_optional_u64(flags, "--after-unix-ms")?;
    let after_request_id = parse_optional_string_value(flags, "--after-request-id")?;
    let filters = parse_session_event_filters(instance, game, server, flags)?;
    session_events_payload(
        state_dir,
        limit,
        after_unix_ms,
        after_request_id.as_deref(),
        &filters,
    )
}

fn run_session_events_wait(
    flags: &FlagArgs,
    state_dir: &Path,
    instance: Option<String>,
    game: Option<String>,
    server: Option<String>,
) -> CliOutcome<Value> {
    flags.expect_positionals("session events wait", 1)?;
    let timeout =
        parse_optional_duration_ms(flags, "--timeout-ms", SESSION_DAEMON_REQUEST_TIMEOUT_MS)?;
    let poll = parse_optional_duration_ms(flags, "--poll-ms", 100)?;
    if poll.is_zero() || poll > Duration::from_millis(5_000) {
        return Err(CliError::usage("--poll-ms must be between 1 and 5000"));
    }
    let list_flags = flags.without_first_positional();
    let started = Instant::now();
    loop {
        let mut payload = session_events_query_payload(
            state_dir,
            &list_flags,
            instance.clone(),
            game.clone(),
            server.clone(),
        )?;
        let event_count = payload
            .get("event_count")
            .and_then(Value::as_u64)
            .unwrap_or(0);
        if event_count > 0 {
            payload["wait"] = json!({
                "completed": true,
                "timed_out": false,
                "elapsed_ms": started.elapsed().as_millis() as u64,
                "timeout_ms": timeout.as_millis() as u64,
                "poll_ms": poll.as_millis() as u64
            });
            return Ok(payload);
        }
        if started.elapsed() >= timeout {
            payload["wait"] = json!({
                "completed": false,
                "timed_out": true,
                "elapsed_ms": started.elapsed().as_millis() as u64,
                "timeout_ms": timeout.as_millis() as u64,
                "poll_ms": poll.as_millis() as u64
            });
            return Ok(payload);
        }
        thread::sleep(poll.min(timeout.saturating_sub(started.elapsed())));
    }
}

fn run_session_response(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "response", args);
    }
    run_session_response_in_state_dir(&flags, &session_state_dir_from_flags(&flags)?)
}

fn run_session_response_in_state_dir(flags: &FlagArgs, state_dir: &Path) -> CliOutcome<Value> {
    let sub = flags
        .positionals
        .first()
        .map(String::as_str)
        .ok_or_else(|| CliError::usage("session response requires get or wait <request-id>"))?;
    match sub {
        "get" => run_session_response_get(flags, state_dir),
        "wait" => run_session_response_wait(flags, state_dir),
        other => Err(CliError::usage(format!(
            "unknown session response command: {other}"
        ))),
    }
}

fn run_session_response_get(flags: &FlagArgs, state_dir: &Path) -> CliOutcome<Value> {
    flags.expect_positionals("session response get", 2)?;
    let request_id = flags.required_positional(1, "request-id")?;
    validate_session_request_id(request_id)?;
    let consume = flags.bool("--consume");
    session_response_payload(state_dir, request_id, consume, None)
}

fn run_session_response_wait(flags: &FlagArgs, state_dir: &Path) -> CliOutcome<Value> {
    flags.expect_positionals("session response wait", 2)?;
    let request_id = flags.required_positional(1, "request-id")?;
    validate_session_request_id(request_id)?;
    let consume = flags.bool("--consume");
    let timeout =
        parse_optional_duration_ms(flags, "--timeout-ms", SESSION_DAEMON_REQUEST_TIMEOUT_MS)?;
    let poll = parse_optional_duration_ms(flags, "--poll-ms", 100)?;
    if poll.is_zero() || poll > Duration::from_millis(5_000) {
        return Err(CliError::usage("--poll-ms must be between 1 and 5000"));
    }
    let response_path = session_responses_dir(state_dir).join(format!("{request_id}.json"));
    let started = Instant::now();
    loop {
        if response_path.exists() {
            let elapsed_ms = started.elapsed().as_millis() as u64;
            return session_response_payload(
                state_dir,
                request_id,
                consume,
                Some(json!({
                    "completed": true,
                    "elapsed_ms": elapsed_ms,
                    "timeout_ms": timeout.as_millis() as u64,
                    "poll_ms": poll.as_millis() as u64
                })),
            );
        }
        if started.elapsed() >= timeout {
            return Err(CliError::runtime_not_running(format!(
                "session response {request_id} timed out after {} ms in {}",
                timeout.as_millis(),
                session_responses_dir(state_dir).display()
            )));
        }
        thread::sleep(poll.min(timeout.saturating_sub(started.elapsed())));
    }
}

fn session_response_payload(
    state_dir: &Path,
    request_id: &str,
    consume: bool,
    wait: Option<Value>,
) -> CliOutcome<Value> {
    let response_path = session_responses_dir(state_dir).join(format!("{request_id}.json"));
    let response = read_pending_session_response(&response_path)?.ok_or_else(|| {
        CliError::runtime_not_running(format!(
            "session response {request_id} is not available in {}",
            session_responses_dir(state_dir).display()
        ))
    })?;
    if response.request_id != request_id {
        return Err(CliError::runtime_not_running(format!(
            "session response id mismatch: expected {request_id}, found {}",
            response.request_id
        )));
    }
    let data_summary = session_request_data_summary(&response);
    if consume {
        fs::remove_file(&response_path).map_err(|err| {
            CliError::runtime_not_running(format!(
                "failed to consume session response {}: {err}",
                response_path.display()
            ))
        })?;
    }
    let mut payload = json!({
        "schema_version": "session.response.v0.1",
        "state_dir": state_dir.display().to_string(),
        "request_id": request_id,
        "consumed": consume,
        "response_path": response_path.display().to_string(),
        "response": response,
        "data_summary": data_summary
    });
    if let Some(wait) = wait {
        payload["wait"] = wait;
    }
    Ok(payload)
}

fn run_session_request_state(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "request_state", args);
    }
    run_session_request_state_in_state_dir(global, &flags, &session_state_dir_from_flags(&flags)?)
}

fn run_session_request_state_in_state_dir(
    global: &GlobalOptions,
    flags: &FlagArgs,
    state_dir: &Path,
) -> CliOutcome<Value> {
    let sub = flags
        .positionals
        .first()
        .map(String::as_str)
        .ok_or_else(|| {
            CliError::usage(
                "session request-state requires get <request-id>, wait <request-id>, or list",
            )
        })?;
    match sub {
        "get" => run_session_request_state_get(flags, state_dir),
        "wait" => run_session_request_state_wait(flags, state_dir),
        "list" => run_session_request_state_list(global, flags, state_dir),
        other => Err(CliError::usage(format!(
            "unknown session request-state command: {other}"
        ))),
    }
}

fn run_session_request_state_get(flags: &FlagArgs, state_dir: &Path) -> CliOutcome<Value> {
    flags.expect_positionals("session request-state get", 2)?;
    let request_id = flags.required_positional(1, "request-id")?;
    validate_session_request_id(request_id)?;
    session_request_state_payload(state_dir, request_id)
}

fn run_session_request_state_wait(flags: &FlagArgs, state_dir: &Path) -> CliOutcome<Value> {
    flags.expect_positionals("session request-state wait", 2)?;
    let request_id = flags.required_positional(1, "request-id")?;
    validate_session_request_id(request_id)?;
    let expected_statuses = parse_session_request_state_wait_status_filter(flags)?;
    let expected_status_set = expected_statuses
        .iter()
        .map(String::as_str)
        .collect::<BTreeSet<_>>();
    let timeout =
        parse_optional_duration_ms(flags, "--timeout-ms", SESSION_DAEMON_REQUEST_TIMEOUT_MS)?;
    let poll = parse_optional_duration_ms(flags, "--poll-ms", 100)?;
    if poll.is_zero() || poll > Duration::from_millis(5_000) {
        return Err(CliError::usage("--poll-ms must be between 1 and 5000"));
    }
    let started = Instant::now();
    loop {
        let mut payload = session_request_state_payload(state_dir, request_id)?;
        let status = payload
            .get("status")
            .and_then(Value::as_str)
            .unwrap_or("unknown")
            .to_string();
        if expected_status_set.contains(status.as_str()) {
            payload["wait"] = json!({
                "completed": true,
                "timed_out": false,
                "matched_status": status,
                "expected_statuses": expected_statuses,
                "elapsed_ms": started.elapsed().as_millis() as u64,
                "timeout_ms": timeout.as_millis() as u64,
                "poll_ms": poll.as_millis() as u64
            });
            return Ok(payload);
        }
        if started.elapsed() >= timeout {
            payload["wait"] = json!({
                "completed": false,
                "timed_out": true,
                "current_status": status,
                "expected_statuses": expected_statuses,
                "elapsed_ms": started.elapsed().as_millis() as u64,
                "timeout_ms": timeout.as_millis() as u64,
                "poll_ms": poll.as_millis() as u64
            });
            return Ok(payload);
        }
        thread::sleep(poll.min(timeout.saturating_sub(started.elapsed())));
    }
}

#[derive(Debug)]
struct SessionRequestStateListItem {
    request_id: String,
    status: &'static str,
    global: Option<SessionCommandGlobal>,
    lease: Option<SessionCommandLease>,
    timestamp_unix_ms: u64,
    priority: u8,
    value: Value,
}

#[derive(Debug)]
struct SessionRequestStateListFilters {
    statuses: Vec<String>,
    target: SessionEventTargetFilter,
}

fn run_session_request_state_list(
    global: &GlobalOptions,
    flags: &FlagArgs,
    state_dir: &Path,
) -> CliOutcome<Value> {
    flags.expect_positionals("session request-state list", 1)?;
    let limit = parse_optional_usize(flags, "--limit", 20)?;
    if limit == 0 || limit > 1_000 {
        return Err(CliError::usage("--limit must be between 1 and 1000"));
    }
    let filters = parse_session_request_state_list_filters(global, flags)?;
    session_request_state_list_payload(state_dir, limit, &filters)
}

fn parse_session_request_state_list_filters(
    global: &GlobalOptions,
    flags: &FlagArgs,
) -> CliOutcome<SessionRequestStateListFilters> {
    Ok(SessionRequestStateListFilters {
        statuses: parse_session_request_state_list_status_filter(flags)?,
        target: parse_session_event_target_filter(
            global.instance.clone(),
            global.game.clone(),
            global.server.clone(),
            flags,
        )?,
    })
}

fn parse_session_request_state_list_status_filter(flags: &FlagArgs) -> CliOutcome<Vec<String>> {
    let statuses = parse_optional_string_values(flags, "--status")?;
    for status in &statuses {
        if !matches!(
            status.as_str(),
            "queued" | "running" | "response_available" | "completed" | "failed"
        ) {
            return Err(CliError::usage(format!(
                "unsupported session request-state list --status value: {status}; expected queued, running, response_available, completed, or failed"
            )));
        }
    }
    Ok(statuses)
}

fn parse_session_request_state_wait_status_filter(flags: &FlagArgs) -> CliOutcome<Vec<String>> {
    let mut statuses = parse_optional_string_values(flags, "--status")?;
    if statuses.is_empty() {
        statuses = SESSION_REQUEST_STATE_WAIT_DEFAULT_STATUSES
            .iter()
            .map(|status| (*status).to_string())
            .collect();
    }
    for status in &statuses {
        if !SESSION_REQUEST_STATE_WAIT_ALLOWED_STATUSES.contains(&status.as_str()) {
            return Err(CliError::usage(format!(
                "unsupported session request-state wait --status value: {status}; expected queued, running, response_available, completed, failed, or unknown"
            )));
        }
    }
    Ok(statuses)
}

fn session_request_state_list_payload(
    state_dir: &Path,
    limit: usize,
    filters: &SessionRequestStateListFilters,
) -> CliOutcome<Value> {
    let requests_dir = session_requests_dir(state_dir);
    let running_dir = session_running_dir(state_dir);
    let responses_dir = session_responses_dir(state_dir);
    let mut items_by_id: BTreeMap<String, SessionRequestStateListItem> = BTreeMap::new();
    let mut disappeared_requests = 0usize;
    let mut disappeared_running = 0usize;
    let mut disappeared_responses = 0usize;

    for path in sorted_json_paths(&requests_dir)? {
        let Some(request) = read_pending_session_request(&path)? else {
            disappeared_requests += 1;
            continue;
        };
        let request_id = request.request_id.clone();
        let response_path = responses_dir.join(format!("{request_id}.json"));
        insert_request_state_list_item(
            &mut items_by_id,
            SessionRequestStateListItem {
                request_id: request_id.clone(),
                status: "queued",
                global: Some(request.global.clone()),
                lease: request.lease.clone(),
                timestamp_unix_ms: request.created_at_unix_ms,
                priority: 2,
                value: json!({
                    "request_id": request_id,
                    "status": "queued",
                    "known": true,
                    "source": "pending_request",
                    "command": request.command,
                    "global": request.global,
                    "lease": request.lease,
                    "args_count": request.args.len(),
                    "created_at_unix_ms": request.created_at_unix_ms,
                    "paths": {
                        "request": path.display().to_string(),
                        "response": response_path.display().to_string()
                    }
                }),
            },
        );
    }

    for path in sorted_json_paths(&running_dir)? {
        let Some(request) = read_running_session_request(&path)? else {
            disappeared_running += 1;
            continue;
        };
        let request_id = request.request_id.clone();
        let request_path = requests_dir.join(format!("{request_id}.json"));
        let response_path = responses_dir.join(format!("{request_id}.json"));
        insert_request_state_list_item(
            &mut items_by_id,
            SessionRequestStateListItem {
                request_id: request_id.clone(),
                status: "running",
                global: Some(request.global.clone()),
                lease: request.lease.clone(),
                timestamp_unix_ms: request.started_at_unix_ms,
                priority: 1,
                value: json!({
                    "request_id": request_id,
                    "status": "running",
                    "known": true,
                    "source": "running_request",
                    "command": request.command,
                    "global": request.global,
                    "lease": request.lease,
                    "args_count": request.args.len(),
                    "created_at_unix_ms": request.created_at_unix_ms,
                    "started_at_unix_ms": request.started_at_unix_ms,
                    "paths": {
                        "request": request_path.display().to_string(),
                        "running": path.display().to_string(),
                        "response": response_path.display().to_string()
                    }
                }),
            },
        );
    }

    for path in sorted_json_paths(&responses_dir)? {
        let Some(response) = read_pending_session_response(&path)? else {
            disappeared_responses += 1;
            continue;
        };
        let data_summary = session_request_data_summary(&response);
        let request_id = response.request_id.clone();
        let request_path = requests_dir.join(format!("{request_id}.json"));
        insert_request_state_list_item(
            &mut items_by_id,
            SessionRequestStateListItem {
                request_id: request_id.clone(),
                status: "response_available",
                global: None,
                lease: None,
                timestamp_unix_ms: response.completed_at_unix_ms,
                priority: 0,
                value: json!({
                    "request_id": request_id,
                    "status": "response_available",
                    "known": true,
                    "source": "pending_response",
                    "command": response.command,
                    "ok": response.ok,
                    "error": response.error,
                    "data_summary": data_summary,
                    "started_at_unix_ms": response.started_at_unix_ms,
                    "completed_at_unix_ms": response.completed_at_unix_ms,
                    "paths": {
                        "request": request_path.display().to_string(),
                        "response": path.display().to_string()
                    }
                }),
            },
        );
    }

    let journal_entries = read_session_request_journal(state_dir, 1_000)?;
    let journal_entries_scanned = journal_entries.len();
    for entry in journal_entries.into_iter().rev() {
        let event = session_request_event_json(&entry);
        let request_id = entry.request_id.clone();
        let status = session_request_event_status(&entry);
        insert_request_state_list_item(
            &mut items_by_id,
            SessionRequestStateListItem {
                request_id: request_id.clone(),
                status,
                global: entry.global.clone(),
                lease: entry.lease.clone(),
                timestamp_unix_ms: entry.completed_at_unix_ms,
                priority: 3,
                value: json!({
                    "request_id": request_id,
                    "status": status,
                    "known": true,
                    "source": "request_journal",
                    "command": entry.command,
                    "global": entry.global,
                    "lease": entry.lease,
                    "args_count": entry.args.len(),
                    "ok": entry.ok,
                    "error": entry.error,
                    "data_summary": entry.data_summary,
                    "created_at_unix_ms": entry.created_at_unix_ms,
                    "started_at_unix_ms": entry.started_at_unix_ms,
                    "completed_at_unix_ms": entry.completed_at_unix_ms,
                    "journal_event": event,
                    "paths": {
                        "journal": session_request_journal_path(state_dir).display().to_string()
                    }
                }),
            },
        );
    }

    let status_filter_set = filters
        .statuses
        .iter()
        .map(String::as_str)
        .collect::<BTreeSet<_>>();
    let mut all_items = items_by_id.into_values().collect::<Vec<_>>();
    all_items.sort_by(|left, right| {
        right
            .timestamp_unix_ms
            .cmp(&left.timestamp_unix_ms)
            .then_with(|| left.request_id.cmp(&right.request_id))
    });
    let status_counts = request_state_status_counts(&all_items);
    let mut filtered_items = all_items
        .into_iter()
        .filter(|item| {
            (status_filter_set.is_empty() || status_filter_set.contains(item.status))
                && filters
                    .target
                    .matches_parts(item.global.as_ref(), item.lease.as_ref())
        })
        .collect::<Vec<_>>();
    let total_matching = filtered_items.len();
    if filtered_items.len() > limit {
        filtered_items.truncate(limit);
    }
    let items = filtered_items
        .into_iter()
        .map(|item| item.value)
        .collect::<Vec<_>>();

    Ok(json!({
        "schema_version": "session.request_state_list.v0.1",
        "state_dir": state_dir.display().to_string(),
        "limit": limit,
        "status_filter": if filters.statuses.is_empty() {
            Value::Null
        } else {
            json!(&filters.statuses)
        },
        "target_filter": filters.target.to_json(),
        "total_matching": total_matching,
        "item_count": items.len(),
        "counts": status_counts,
        "sources": {
            "requests_dir": requests_dir.display().to_string(),
            "running_dir": running_dir.display().to_string(),
            "responses_dir": responses_dir.display().to_string(),
            "journal": session_request_journal_path(state_dir).display().to_string(),
            "journal_entries_scanned": journal_entries_scanned,
            "disappeared_requests_during_read": disappeared_requests,
            "disappeared_running_during_read": disappeared_running,
            "disappeared_responses_during_read": disappeared_responses
        },
        "items": items
    }))
}

fn sorted_json_paths(dir: &Path) -> CliOutcome<Vec<PathBuf>> {
    let mut paths = file_paths_with_extension(dir, "json")?;
    paths.sort_by_key(|path| {
        path.file_name()
            .map(|value| value.to_string_lossy().into_owned())
            .unwrap_or_default()
    });
    Ok(paths)
}

fn insert_request_state_list_item(
    items: &mut BTreeMap<String, SessionRequestStateListItem>,
    item: SessionRequestStateListItem,
) {
    let should_insert = items
        .get(&item.request_id)
        .is_none_or(|existing| item.priority < existing.priority);
    if should_insert {
        items.insert(item.request_id.clone(), item);
    }
}

fn request_state_status_counts(items: &[SessionRequestStateListItem]) -> Value {
    let mut queued = 0usize;
    let mut running = 0usize;
    let mut response_available = 0usize;
    let mut completed = 0usize;
    let mut failed = 0usize;
    for item in items {
        match item.status {
            "queued" => queued += 1,
            "running" => running += 1,
            "response_available" => response_available += 1,
            "completed" => completed += 1,
            "failed" => failed += 1,
            _ => {}
        }
    }
    json!({
        "total": items.len(),
        "queued": queued,
        "running": running,
        "response_available": response_available,
        "completed": completed,
        "failed": failed
    })
}

fn session_request_state_payload(state_dir: &Path, request_id: &str) -> CliOutcome<Value> {
    let request_path = session_requests_dir(state_dir).join(format!("{request_id}.json"));
    let running_path = session_running_request_path(state_dir, request_id);
    let response_path = session_responses_dir(state_dir).join(format!("{request_id}.json"));
    let pending_request = read_pending_session_request(&request_path)?;
    let running_request = read_running_session_request(&running_path)?;
    let pending_response = read_pending_session_response(&response_path)?;
    let journal_entry = read_session_request_journal(state_dir, 1_000)?
        .into_iter()
        .rev()
        .find(|entry| entry.request_id == request_id);
    let status = if pending_response.is_some() {
        "response_available"
    } else if running_request.is_some() {
        "running"
    } else if pending_request.is_some() {
        "queued"
    } else if let Some(entry) = journal_entry.as_ref() {
        session_request_event_status(entry)
    } else {
        "unknown"
    };
    let known = status != "unknown";
    let response_summary = pending_response
        .as_ref()
        .and_then(session_request_data_summary);
    let journal_event = journal_entry.as_ref().map(session_request_event_json);

    Ok(json!({
        "schema_version": "session.request_state.v0.1",
        "state_dir": state_dir.display().to_string(),
        "request_id": request_id,
        "status": status,
        "known": known,
        "paths": {
            "request": request_path.display().to_string(),
            "running": running_path.display().to_string(),
            "response": response_path.display().to_string(),
            "journal": session_request_journal_path(state_dir).display().to_string()
        },
        "pending_request": pending_request,
        "running_request": running_request,
        "pending_response": pending_response,
        "response_data_summary": response_summary,
        "journal_entry": journal_entry,
        "journal_event": journal_event
    }))
}

fn session_events_payload(
    state_dir: &Path,
    limit: usize,
    after_unix_ms: Option<u64>,
    after_request_id: Option<&str>,
    filters: &SessionEventFilters,
) -> CliOutcome<Value> {
    if limit == 0 || limit > 1_000 {
        return Err(CliError::usage("--limit must be between 1 and 1000"));
    }
    let read_limit = if after_unix_ms.is_some() || after_request_id.is_some() || filters.is_active()
    {
        1_000
    } else {
        limit
    };
    let mut entries = read_session_request_journal(state_dir, read_limit)?;
    if let Some(cursor_request_id) = after_request_id {
        let Some(position) = entries
            .iter()
            .position(|entry| entry.request_id == cursor_request_id)
        else {
            return Err(CliError::new(
                ErrorKind::UsageValidation,
                "event_cursor_not_found",
                format!(
                    "request cursor '{cursor_request_id}' was not found in the recent request journal"
                ),
                &["request_journal"],
            ));
        };
        entries.drain(0..=position);
    }
    let mut entries = entries
        .into_iter()
        .filter(|entry| {
            after_unix_ms
                .map(|after| entry.completed_at_unix_ms > after)
                .unwrap_or(true)
        })
        .filter(|entry| filters.matches(entry))
        .collect::<Vec<_>>();
    if entries.len() > limit {
        let keep_from = entries.len() - limit;
        entries.drain(0..keep_from);
    }
    let events = entries
        .iter()
        .map(session_request_event_json)
        .collect::<Vec<_>>();
    let latest_timestamp_unix_ms = entries.iter().map(|entry| entry.completed_at_unix_ms).max();
    let latest_request_id = entries.last().map(|entry| entry.request_id.as_str());
    Ok(json!({
        "schema_version": "session.events.v0.1",
        "state_dir": state_dir.display().to_string(),
        "source": "request_journal",
        "journal": session_request_journal_path(state_dir).display().to_string(),
        "limit": limit,
        "after_unix_ms": after_unix_ms,
        "after_request_id": after_request_id,
        "command_filter": if filters.commands.is_empty() {
            Value::Null
        } else {
            json!(&filters.commands)
        },
        "data_summary_kind_filter": if filters.data_summary_kinds.is_empty() {
            Value::Null
        } else {
            json!(&filters.data_summary_kinds)
        },
        "status_filter": if filters.statuses.is_empty() {
            Value::Null
        } else {
            json!(&filters.statuses)
        },
        "target_filter": filters.target.to_json(),
        "event_count": events.len(),
        "cursor": {
            "latest_timestamp_unix_ms": latest_timestamp_unix_ms,
            "next_after_unix_ms": latest_timestamp_unix_ms,
            "latest_request_id": latest_request_id,
            "next_after_request_id": latest_request_id
        },
        "events": events
    }))
}

fn parse_session_event_status_filter(flags: &FlagArgs) -> CliOutcome<Vec<String>> {
    let status_filter = parse_optional_string_values(flags, "--status")?;
    for status in &status_filter {
        if !matches!(status.as_str(), "completed" | "failed") {
            return Err(CliError::usage(format!(
                "unsupported session events --status value: {status}; expected completed or failed"
            )));
        }
    }
    Ok(status_filter)
}

fn parse_session_event_filters(
    instance: Option<String>,
    game: Option<String>,
    server: Option<String>,
    flags: &FlagArgs,
) -> CliOutcome<SessionEventFilters> {
    Ok(SessionEventFilters {
        commands: parse_optional_string_values(flags, "--command")?,
        data_summary_kinds: parse_optional_string_values(flags, "--data-summary-kind")?,
        statuses: parse_session_event_status_filter(flags)?,
        target: parse_session_event_target_filter(instance, game, server, flags)?,
    })
}

fn parse_session_event_target_filter(
    instance: Option<String>,
    game: Option<String>,
    server: Option<String>,
    flags: &FlagArgs,
) -> CliOutcome<SessionEventTargetFilter> {
    Ok(SessionEventTargetFilter {
        instance,
        game,
        server,
        lease_holders: parse_optional_string_values(flags, "--lease-holder")?,
    })
}

impl SessionEventFilters {
    fn is_active(&self) -> bool {
        !self.commands.is_empty()
            || !self.data_summary_kinds.is_empty()
            || !self.statuses.is_empty()
            || self.target.is_active()
    }

    fn read_limit(&self, limit: usize) -> usize {
        if self.is_active() { 1_000 } else { limit }
    }

    fn matches(&self, entry: &SessionRequestJournalEntry) -> bool {
        self.command_matches(entry)
            && self.data_summary_kind_matches(entry)
            && self.status_matches(entry)
            && self.target.matches(entry)
    }

    fn command_matches(&self, entry: &SessionRequestJournalEntry) -> bool {
        self.commands.is_empty()
            || self
                .commands
                .iter()
                .any(|command| command == &entry.command)
    }

    fn data_summary_kind_matches(&self, entry: &SessionRequestJournalEntry) -> bool {
        self.data_summary_kinds.is_empty()
            || entry
                .data_summary
                .as_ref()
                .and_then(|summary| summary.get("kind"))
                .and_then(Value::as_str)
                .is_some_and(|kind| {
                    self.data_summary_kinds
                        .iter()
                        .any(|filtered| filtered == kind)
                })
    }

    fn status_matches(&self, entry: &SessionRequestJournalEntry) -> bool {
        self.statuses.is_empty()
            || self
                .statuses
                .iter()
                .any(|status| status.as_str() == session_request_event_status(entry))
    }
}

impl SessionEventTargetFilter {
    fn is_active(&self) -> bool {
        self.instance.is_some()
            || self.game.is_some()
            || self.server.is_some()
            || !self.lease_holders.is_empty()
    }

    fn matches(&self, entry: &SessionRequestJournalEntry) -> bool {
        self.matches_parts(entry.global.as_ref(), entry.lease.as_ref())
    }

    fn matches_parts(
        &self,
        global: Option<&SessionCommandGlobal>,
        lease: Option<&SessionCommandLease>,
    ) -> bool {
        if !optional_selector_matches(
            global.and_then(|global| global.instance.as_deref()),
            self.instance.as_deref(),
        ) {
            return false;
        }
        if !optional_selector_matches(
            global.and_then(|global| global.game.as_deref()),
            self.game.as_deref(),
        ) {
            return false;
        }
        if !optional_selector_matches(
            global.and_then(|global| global.server.as_deref()),
            self.server.as_deref(),
        ) {
            return false;
        }
        if !self.lease_holders.is_empty()
            && !lease.is_some_and(|lease| {
                self.lease_holders
                    .iter()
                    .any(|holder| holder == &lease.holder)
            })
        {
            return false;
        }
        true
    }

    fn to_json(&self) -> Value {
        if !self.is_active() {
            return Value::Null;
        }
        json!({
            "instance": &self.instance,
            "game": &self.game,
            "server": &self.server,
            "lease_holders": if self.lease_holders.is_empty() {
                Value::Null
            } else {
                json!(&self.lease_holders)
            }
        })
    }
}

fn optional_selector_matches(actual: Option<&str>, expected: Option<&str>) -> bool {
    match expected {
        Some(expected) => actual == Some(expected),
        None => true,
    }
}

fn session_request_event_status(entry: &SessionRequestJournalEntry) -> &'static str {
    if entry.ok { "completed" } else { "failed" }
}

fn session_request_event_json(entry: &SessionRequestJournalEntry) -> Value {
    let status = session_request_event_status(entry);
    let event_type = if entry.ok {
        "session.request.completed"
    } else {
        "session.request.failed"
    };
    let lease = entry.lease.as_ref().map(|lease| {
        json!({
            "holder": &lease.holder,
            "lease_id": &lease.lease_id
        })
    });
    let error = entry.error.as_ref().map(|error| {
        json!({
            "code": &error.code,
            "message": &error.message,
            "blocked_by": &error.blocked_by
        })
    });
    json!({
        "schema_version": "session.event.v0.1",
        "type": event_type,
        "timestamp_unix_ms": entry.completed_at_unix_ms,
        "request_id": &entry.request_id,
        "command": &entry.command,
        "global": &entry.global,
        "status": status,
        "ok": entry.ok,
        "args_count": entry.args.len(),
        "lease": lease,
        "error": error,
        "data_summary": entry.data_summary,
        "timing": {
            "created_at_unix_ms": entry.created_at_unix_ms,
            "started_at_unix_ms": entry.started_at_unix_ms,
            "completed_at_unix_ms": entry.completed_at_unix_ms,
            "queue_wait_ms": entry.started_at_unix_ms.saturating_sub(entry.created_at_unix_ms),
            "duration_ms": entry.completed_at_unix_ms.saturating_sub(entry.started_at_unix_ms)
        }
    })
}

fn run_session_journal(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "journal", args);
    }
    flags.expect_positionals("session journal", 0)?;
    let state_dir = session_state_dir_from_flags(&flags)?;
    let limit = parse_optional_usize(&flags, "--limit", 20)?;
    let filters = parse_session_event_filters(
        global.instance.clone(),
        global.game.clone(),
        global.server.clone(),
        &flags,
    )?;
    session_journal_payload(&state_dir, limit, &filters)
}

fn session_journal_payload(
    state_dir: &Path,
    limit: usize,
    filters: &SessionEventFilters,
) -> CliOutcome<Value> {
    if limit == 0 || limit > 1_000 {
        return Err(CliError::usage("--limit must be between 1 and 1000"));
    }
    let mut entries = read_session_request_journal(state_dir, filters.read_limit(limit))?
        .into_iter()
        .filter(|entry| filters.matches(entry))
        .collect::<Vec<_>>();
    if entries.len() > limit {
        let keep_from = entries.len() - limit;
        entries.drain(0..keep_from);
    }
    Ok(json!({
        "state_dir": state_dir.display().to_string(),
        "journal": session_request_journal_path(state_dir).display().to_string(),
        "limit": limit,
        "command_filter": if filters.commands.is_empty() {
            Value::Null
        } else {
            json!(&filters.commands)
        },
        "data_summary_kind_filter": if filters.data_summary_kinds.is_empty() {
            Value::Null
        } else {
            json!(&filters.data_summary_kinds)
        },
        "status_filter": if filters.statuses.is_empty() {
            Value::Null
        } else {
            json!(&filters.statuses)
        },
        "target_filter": filters.target.to_json(),
        "entries": entries
    }))
}

fn run_session_monitor_policy(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    args.first()
        .ok_or_else(|| CliError::usage("session monitor-policy requires status|set|clear"))?;
    let flags = FlagArgs::parse(&args[1..])?;
    let state_dir = session_state_dir_from_flags(&flags)?;
    run_session_monitor_policy_in_state_dir(global, args, &state_dir, false)
}

fn run_session_monitor_policy_in_state_dir(
    global: &GlobalOptions,
    args: &[String],
    state_dir: &Path,
    daemon_owned: bool,
) -> CliOutcome<Value> {
    let action = args
        .first()
        .map(String::as_str)
        .ok_or_else(|| CliError::usage("session monitor-policy requires status|set|clear"))?;
    let flags = FlagArgs::parse(&args[1..])?;
    match action {
        "status" => {
            flags.expect_positionals("session monitor-policy status", 0)?;
            session_monitor_policy_payload(state_dir)
        }
        "set" => {
            flags.expect_positionals("session monitor-policy set", 0)?;
            let interval = parse_optional_duration_ms(&flags, "--interval-ms", 30_000)?;
            let interval_ms = interval.as_millis() as u64;
            if interval_ms < SESSION_MONITOR_POLICY_MIN_INTERVAL_MS {
                return Err(CliError::usage(format!(
                    "--interval-ms must be at least {SESSION_MONITOR_POLICY_MIN_INTERVAL_MS}"
                )));
            }
            let recover_enabled = flags.bool("--recover");
            let lease = session_monitor_policy_lease(&flags, recover_enabled)?;
            let monitor_args = monitor_policy_monitor_args(&args[1..], &flags)?;
            let now = current_unix_ms();
            let existing =
                read_json_file::<SessionMonitorPolicy>(&session_monitor_policy_path(state_dir))?;
            let created_at = existing
                .as_ref()
                .map(|policy| policy.created_at_unix_ms)
                .unwrap_or(now);
            let policy = SessionMonitorPolicy {
                schema_version: "session.monitor_policy.v0.1".to_string(),
                enabled: true,
                interval_ms,
                global: SessionCommandGlobal::from_global(global),
                args: monitor_args,
                read_only: !recover_enabled,
                recover_enabled,
                lease,
                created_at_unix_ms: created_at,
                updated_at_unix_ms: now,
            };
            write_json_file_atomic(&session_monitor_policy_path(state_dir), &policy)?;
            let state = SessionMonitorState {
                schema_version: "session.monitor_state.v0.1".to_string(),
                policy_updated_at_unix_ms: policy.updated_at_unix_ms,
                next_due_unix_ms: now,
                run_count: 0,
                last_started_at_unix_ms: None,
                last_completed_at_unix_ms: None,
                last_ok: None,
                last_status: None,
                last_result: None,
                last_error: None,
                last_recovery: None,
                last_recovery_error: None,
            };
            write_json_file_atomic(&session_monitor_state_path(state_dir), &state)?;
            Ok(json!({
                "status": "configured",
                "mode": "session_monitor_policy",
                "daemon_owned": daemon_owned,
                "state_dir": state_dir.display().to_string(),
                "policy_path": session_monitor_policy_path(state_dir).display().to_string(),
                "state_path": session_monitor_state_path(state_dir).display().to_string(),
                "policy": policy,
                "state": state
            }))
        }
        "clear" => {
            flags.expect_positionals("session monitor-policy clear", 0)?;
            let policy_path = session_monitor_policy_path(state_dir);
            let existed = policy_path.exists();
            if existed {
                fs::remove_file(&policy_path).map_err(|err| {
                    CliError::usage(format!("failed to remove {}: {err}", policy_path.display()))
                })?;
            }
            Ok(json!({
                "status": "cleared",
                "mode": "session_monitor_policy",
                "daemon_owned": daemon_owned,
                "state_dir": state_dir.display().to_string(),
                "policy_path": policy_path.display().to_string(),
                "policy_existed": existed,
                "state_preserved": session_monitor_state_path(state_dir).exists()
            }))
        }
        other => Err(CliError::usage(format!(
            "unknown session monitor-policy action: {other}"
        ))),
    }
}

fn session_monitor_policy_payload(state_dir: &Path) -> CliOutcome<Value> {
    let policy = read_json_file::<SessionMonitorPolicy>(&session_monitor_policy_path(state_dir))?;
    let state = read_json_file::<SessionMonitorState>(&session_monitor_state_path(state_dir))?;
    let read_only = policy
        .as_ref()
        .map(|policy| policy.read_only)
        .unwrap_or(true);
    let recover_enabled = policy
        .as_ref()
        .map(|policy| policy.recover_enabled)
        .unwrap_or(false);
    Ok(json!({
        "schema_version": "session.monitor_policy_status.v0.1",
        "state_dir": state_dir.display().to_string(),
        "policy_path": session_monitor_policy_path(state_dir).display().to_string(),
        "state_path": session_monitor_state_path(state_dir).display().to_string(),
        "configured": policy.is_some(),
        "policy": policy,
        "state": state,
        "execution_model": {
            "daemon_owned": true,
            "read_only": read_only,
            "runs_monitor_once": true,
            "recover_enabled": recover_enabled,
            "recovery_requires_matching_lease": recover_enabled,
            "recovery_without_matching_lease_status": if recover_enabled { "deferred_by_lease" } else { "not_applicable" },
            "executes_input": recover_enabled,
            "executes_app_restart": false
        }
    }))
}

fn session_monitor_policy_lease(
    flags: &FlagArgs,
    recover_enabled: bool,
) -> CliOutcome<Option<SessionCommandLease>> {
    let lease = session_command_lease_from_flags(flags);
    if recover_enabled && lease.is_none() {
        return Err(CliError::safety_blocked(
            "monitor_policy_recovery_requires_lease",
            "session monitor-policy --recover requires --lease-holder <id> and an active matching lease at execution time",
            &["lab_lease", "monitor_policy"],
        ));
    }
    Ok(lease)
}

fn monitor_policy_monitor_args(raw_args: &[String], flags: &FlagArgs) -> CliOutcome<Vec<String>> {
    if flags.optional("--max-iterations").is_some() {
        return Err(CliError::usage(
            "session monitor-policy stores monitor --once arguments; do not use --max-iterations",
        ));
    }
    if flags.bool("--via-daemon") || flags.bool("--local") {
        return Err(CliError::usage(
            "session monitor-policy set does not store --via-daemon or --local",
        ));
    }
    if !flags.bool("--capture") && flags.optional("--scene").is_none() {
        return Err(CliError::usage(
            "session monitor-policy set requires --scene <png> or --capture",
        ));
    }
    let mut out = Vec::new();
    let mut index = 0usize;
    while index < raw_args.len() {
        let arg = &raw_args[index];
        if [
            "--interval-ms",
            "--state-dir",
            "--request-timeout-ms",
            "--lease-holder",
            "--holder",
            "--lease-id",
        ]
        .contains(&arg.as_str())
        {
            index += if index + 1 < raw_args.len() && !raw_args[index + 1].starts_with("--") {
                2
            } else {
                1
            };
            continue;
        }
        if ["--recover", "--via-daemon", "--local", "--max-iterations"].contains(&arg.as_str()) {
            if arg == "--recover" {
                index += 1;
                continue;
            }
            return Err(CliError::usage(format!(
                "session monitor-policy set cannot store {arg}"
            )));
        }
        out.push(arg.clone());
        index += 1;
    }
    Ok(out)
}

fn run_session_status(global: &GlobalOptions, args: &[String]) -> CliOutcome<Value> {
    let flags = FlagArgs::parse(args)?;
    if should_route_readonly_via_session_daemon(global, &flags)? {
        return submit_readonly_session_request(global, &flags, "status", args);
    }
    flags.expect_positionals("session status", 0)?;
    let state_dir = session_state_dir_from_flags(&flags)?;
    let diagnostics = flags.bool("--diagnostics");
    let config = if diagnostics {
        Some(read_user_config()?)
    } else {
        None
    };
    session_status_payload_with_config(&state_dir, diagnostics, config.as_ref())
}

#[cfg(test)]
fn session_status_payload(state_dir: &Path, diagnostics: bool) -> CliOutcome<Value> {
    session_status_payload_with_config(state_dir, diagnostics, None)
}

fn session_status_payload_with_config(
    state_dir: &Path,
    diagnostics: bool,
    config: Option<&UserConfig>,
) -> CliOutcome<Value> {
    let info_path = session_info_path(state_dir);
    let heartbeat_path = session_heartbeat_path(state_dir);
    let info = read_json_file::<SessionInfo>(&info_path)?;
    let heartbeat = read_json_file::<SessionHeartbeat>(&heartbeat_path)?;
    let diagnostics_payload = if diagnostics {
        Some(session_status_diagnostics(
            state_dir,
            info.as_ref(),
            heartbeat.as_ref(),
            current_unix_ms(),
            config,
        )?)
    } else {
        None
    };
    let mut status = json!({
        "state_dir": state_dir.display().to_string(),
        "running": info.is_some(),
        "info": info,
        "heartbeat": heartbeat
    });
    if let Some(diagnostics) = diagnostics_payload {
        status["diagnostics"] = diagnostics;
    }
    Ok(status)
}

fn session_status_diagnostics(
    state_dir: &Path,
    info: Option<&SessionInfo>,
    heartbeat: Option<&SessionHeartbeat>,
    now_ms: u64,
    config: Option<&UserConfig>,
) -> CliOutcome<Value> {
    let recent_entries = read_session_request_journal(state_dir, 5)?;
    let last_entry = recent_entries.last();
    let last_error = recent_entries.iter().rev().find(|entry| !entry.ok);
    let liveness = session_liveness_snapshot(info, heartbeat, now_ms);
    let monitor_policy = session_monitor_policy_payload(state_dir)?;
    let queue_health = session_queue_health(state_dir, now_ms, SESSION_DAEMON_REQUEST_TIMEOUT_MS)?;
    let recommended_actions = session_status_recommended_actions(
        state_dir,
        liveness.status,
        &monitor_policy,
        &queue_health,
        &recent_entries,
    )?;
    Ok(json!({
        "liveness": session_liveness_diagnostics(info, heartbeat, now_ms),
        "recommended_actions": recommended_actions,
        "paths": {
            "info": session_info_path(state_dir).display().to_string(),
            "heartbeat": session_heartbeat_path(state_dir).display().to_string(),
            "requests": session_requests_dir(state_dir).display().to_string(),
            "running": session_running_dir(state_dir).display().to_string(),
            "responses": session_responses_dir(state_dir).display().to_string(),
            "journal": session_request_journal_path(state_dir).display().to_string()
        },
        "queues": {
            "pending_requests": count_files_with_extension(&session_requests_dir(state_dir), "json")?,
            "running_requests": count_files_with_extension(&session_running_dir(state_dir), "json")?,
            "pending_responses": count_files_with_extension(&session_responses_dir(state_dir), "json")?,
            "health": queue_health,
            "pending_request_preview": session_pending_request_preview(
                state_dir,
                SESSION_PENDING_REQUEST_PREVIEW_LIMIT
            )?,
            "running_request_preview": session_running_request_preview(
                state_dir,
                SESSION_PENDING_REQUEST_PREVIEW_LIMIT
            )?,
            "pending_response_preview": session_pending_response_preview(
                state_dir,
                SESSION_PENDING_REQUEST_PREVIEW_LIMIT
            )?
        },
        "instances": session_instance_registry_diagnostics(config),
        "leases": session_lease_diagnostics(state_dir)?,
        "monitor_policy": monitor_policy,
        "phase_c": session_phase_c_diagnostics_summary()?,
        "validation": session_validation_diagnostics_summary(),
        "journal": {
            "exists": session_request_journal_path(state_dir).exists(),
            "path": session_request_journal_path(state_dir).display().to_string(),
            "bytes": file_size_if_exists(&session_request_journal_path(state_dir))?,
            "total_entries": count_session_request_journal_entries(state_dir)?,
            "recent_limit": 5,
            "recent_count": recent_entries.len(),
            "last_entry": last_entry,
            "last_error": last_error,
            "retention": {
                "max_bytes": SESSION_REQUEST_JOURNAL_MAX_BYTES,
                "archive_count": 1,
                "active_rotation": "size"
            },
            "archive": {
                "path": session_request_journal_archive_path(state_dir).display().to_string(),
                "exists": session_request_journal_archive_path(state_dir).exists(),
                "bytes": file_size_if_exists(&session_request_journal_archive_path(state_dir))?
            }
        }
    }))
}

fn session_phase_c_diagnostics_summary() -> CliOutcome<Value> {
    let global = GlobalOptions::default();
    let flags = FlagArgs::default();
    let self_heal_plan = json!({
        "status": "blocked",
        "trigger": {
            "kind": "observe_required"
        },
        "recovery": {
            "kind": "observe_first"
        },
        "ready_to_execute_maintenance": false,
        "escalation": {
            "category": "observe_first",
            "operator_live_validation_required": true
        }
    });
    let transport_plan = session_transport_plan_payload(&flags)?;
    let validation_plan =
        session_validation_plan_payload(&global, &flags, "session validation-plan")?;
    let next_actions =
        session_phase_c_plan_next_actions(&self_heal_plan, &transport_plan, &validation_plan);
    let ordered = next_actions
        .pointer("/ordered")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let ordered_action_kinds: Vec<Value> = ordered
        .iter()
        .filter_map(|item| item.get("action").cloned())
        .collect();

    Ok(json!({
        "schema_version": "session.phase_c_diagnostics.v0.1",
        "phase_c_plan_command": "session phase-c-plan [--endpoint <url>] [--trigger <kind>] [--to <page>]",
        "next_actions": {
            "schema_version": next_actions.get("schema_version").cloned().unwrap_or(Value::Null),
            "status": next_actions.get("status").cloned().unwrap_or(Value::Null),
            "action_count": ordered.len(),
            "first_action": ordered
                .first()
                .and_then(|item| item.get("action"))
                .cloned()
                .unwrap_or(Value::Null),
            "ordered_action_kinds": ordered_action_kinds,
            "self_heal": next_actions.get("self_heal").cloned().unwrap_or(Value::Null),
            "interaction_flow": next_actions.get("interaction_flow").cloned().unwrap_or(Value::Null),
            "trusted_channel": next_actions.get("trusted_channel").cloned().unwrap_or(Value::Null),
            "live_validation": next_actions.get("live_validation").cloned().unwrap_or(Value::Null),
            "guarantees": next_actions.get("guarantees").cloned().unwrap_or(Value::Null)
        }
    }))
}

