    fn append_test_session_journal_response(
        state_dir: &Path,
        request_id: &str,
        command: &str,
        instance: Option<&str>,
        data: Value,
    ) {
        let request = SessionCommandRequest {
            request_id: request_id.to_string(),
            command: command.to_string(),
            global: SessionCommandGlobal {
                instance: instance.map(str::to_string),
                game: None,
                server: None,
                resource_root: None,
                capture_backend: None,
                dry_run: false,
            },
            args: Vec::new(),
            lease: None,
            created_at_unix_ms: 1,
        };
        let response = SessionCommandResponse {
            request_id: request_id.to_string(),
            command: command.to_string(),
            ok: true,
            data: Some(data),
            error: None,
            started_at_unix_ms: 2,
            completed_at_unix_ms: 3,
        };
        append_session_request_journal(state_dir, &request, &response).unwrap();
    }

    fn assert_daemon_request_timeout(result: CliResult) {
        assert_eq!(result.exit_code(), 5);
        assert_eq!(
            result.envelope.error.as_ref().unwrap().code,
            "runtime_not_running"
        );
        assert!(
            result
                .envelope
                .error
                .as_ref()
                .unwrap()
                .message
                .contains("timed out")
        );
    }

