    #[test]
    fn session_stream_plan_reports_interactive_preflight_without_device_work() {
        let _guard = ENV_LOCK.lock().unwrap();
        let temp = TempDir::new().unwrap();
        let config = temp.path().join("config.json");
        unsafe {
            env::set_var(SESSION_STATE_ENV, temp.path());
            env::set_var(CONFIG_ENV, &config);
            env::remove_var(TRUSTED_REMOTE_TOKEN_ENV);
            env::remove_var(TRUSTED_REMOTE_CLIENT_CERT_ENV);
        }
        let result = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "stream-plan",
                "--local",
                "--max-frames",
                "2",
            ],
            true,
        );
        unsafe {
            env::remove_var(SESSION_STATE_ENV);
            env::remove_var(CONFIG_ENV);
        }

        assert_eq!(result.exit_code(), 0);
        let data = result.envelope.data.as_ref().unwrap();
        assert_eq!(
            data.get("schema_version").and_then(Value::as_str),
            Some("session.stream_plan.v0.1")
        );
        assert_eq!(
            data.get("mode").and_then(Value::as_str),
            Some("interactive_stream_preflight")
        );
        assert_eq!(
            data.get("safe_to_open_stream").and_then(Value::as_bool),
            Some(false)
        );
        assert_eq!(
            data.get("safe_to_start_stream").and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/connect_plan/schema_version")
                .and_then(Value::as_str),
            Some("session.connect_plan.v0.1")
        );
        assert_eq!(
            data.pointer("/stream_preflight/schema_version")
                .and_then(Value::as_str),
            Some("session.stream_check.v0.1")
        );
        assert_eq!(
            data.pointer("/stream_preflight/capture/requested_max_frames")
                .and_then(Value::as_u64),
            Some(2)
        );
        assert_eq!(
            data.pointer("/stream_modes/trusted_remote_long_lived/status")
                .and_then(Value::as_str),
            Some("reserved")
        );
        assert_eq!(
            data.pointer("/stream_modes/trusted_remote_long_lived/requires_encryption")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/next_actions/schema_version")
                .and_then(Value::as_str),
            Some("session.stream_next_actions.v0.1")
        );
        assert_eq!(
            data.pointer("/next_actions/ordered/0/action")
                .and_then(Value::as_str),
            Some("resolve_connect_plan_blockers")
        );
        let next_actions = data
            .pointer("/next_actions/ordered")
            .and_then(Value::as_array)
            .unwrap();
        assert!(next_actions.iter().any(|item| {
            item.get("action").and_then(Value::as_str)
                == Some("review_trusted_remote_stream_boundary")
        }));
        assert!(next_actions.iter().any(|item| {
            item.get("action").and_then(Value::as_str) == Some("review_phase_c_plan")
        }));
        assert_eq!(
            data.pointer("/next_actions/phase_c/self_heal_plan_command")
                .and_then(Value::as_str),
            Some("session self-heal-plan [--trigger <kind>] [--to <page>]")
        );
        assert_eq!(
            data.pointer("/next_actions/phase_c/interaction_flow_plan_command")
                .and_then(Value::as_str),
            Some("session stream-plan [--endpoint <url>]")
        );
        assert_eq!(
            data.pointer("/next_actions/trusted_channel/remote_status")
                .and_then(Value::as_str),
            Some("reserved")
        );
        assert_eq!(
            data.pointer("/next_actions/trusted_channel/does_not_start_tls")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/next_actions/live_validation/deferred_code")
                .and_then(Value::as_str),
            Some("requires-live-device")
        );
        assert_eq!(
            data.pointer("/guarantees/does_not_touch_device")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/guarantees/does_not_capture")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/guarantees/does_not_start_listener")
                .and_then(Value::as_bool),
            Some(true)
        );
    }

