    #[test]
    fn session_self_heal_plan_stale_capture_trigger_does_not_require_lease() {
        let _guard = ENV_LOCK.lock().unwrap();
        unsafe {
            env::remove_var(REQUIRE_SESSION_DAEMON_ENV);
        }

        let result = run_cli(
            [
                "--json",
                "session",
                "self-heal-plan",
                "--local",
                "--trigger",
                "capture_stale_suspected",
            ],
            true,
        );

        assert_eq!(result.exit_code(), 0);
        let data = result.envelope.data.as_ref().unwrap();
        assert_eq!(
            data.pointer("/recovery/kind").and_then(Value::as_str),
            Some("capture_backend_recovery")
        );
        assert_eq!(
            data.pointer("/recovery/requires_matching_lease")
                .and_then(Value::as_bool),
            Some(false)
        );
        assert_eq!(
            data.pointer("/lease_gate/required")
                .and_then(Value::as_bool),
            Some(false)
        );
        assert_eq!(
            data.pointer("/lease_gate/status").and_then(Value::as_str),
            Some("not_required")
        );
        assert_eq!(
            data.pointer("/escalation/category").and_then(Value::as_str),
            Some("transient_capture_path")
        );
        assert_eq!(
            data.pointer("/escalation/heavy_recovery_candidate")
                .and_then(Value::as_str),
            Some("app_restart")
        );
        assert_eq!(
            data.pointer("/escalation/does_not_execute_heavy_recovery")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/escalation/must_not_mark_game_frozen_from_adb_screencap_alone")
                .and_then(Value::as_bool),
            Some(true)
        );
        let next_actions = data
            .pointer("/next_actions/ordered")
            .and_then(Value::as_array)
            .expect("self-heal-plan next actions must be an array");
        assert!(next_actions.iter().any(|item| {
            item.get("action").and_then(Value::as_str) == Some("inspect_capture_freshness")
        }));
        assert_eq!(
            data.pointer("/next_actions/recovery/kind")
                .and_then(Value::as_str),
            Some("capture_backend_recovery")
        );
        assert_eq!(
            data.pointer("/next_actions/live_validation/deferred_code")
                .and_then(Value::as_str),
            Some("requires-live-device")
        );
        let blockers = data
            .get("blockers")
            .and_then(Value::as_array)
            .expect("self-heal-plan blockers must be an array");
        assert!(
            !blockers
                .iter()
                .any(|blocker| { blocker.get("kind").and_then(Value::as_str) == Some("lease") })
        );
    }

    #[test]
    fn session_self_heal_plan_control_trigger_requires_lease() {
        let _guard = ENV_LOCK.lock().unwrap();
        unsafe {
            env::remove_var(REQUIRE_SESSION_DAEMON_ENV);
        }

        let result = run_cli(
            [
                "--json",
                "session",
                "self-heal-plan",
                "--local",
                "--trigger",
                "standby",
            ],
            true,
        );

        assert_eq!(result.exit_code(), 0);
        let data = result.envelope.data.as_ref().unwrap();
        assert_eq!(
            data.pointer("/recovery/kind").and_then(Value::as_str),
            Some("standby_wake")
        );
        assert_eq!(
            data.pointer("/recovery/requires_matching_lease")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/lease_gate/required")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/lease_gate/status").and_then(Value::as_str),
            Some("blocked")
        );
        assert_eq!(
            data.pointer("/escalation/category").and_then(Value::as_str),
            Some("maintenance_control_path")
        );
        assert_eq!(
            data.pointer("/escalation/heavy_recovery_requires_matching_lease")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/escalation/operator_live_validation_required")
                .and_then(Value::as_bool),
            Some(true)
        );
        let next_actions = data
            .pointer("/next_actions/ordered")
            .and_then(Value::as_array)
            .expect("self-heal-plan next actions must be an array");
        assert!(next_actions.iter().any(|item| {
            item.get("action").and_then(Value::as_str) == Some("resolve_maintenance_lease")
        }));
        assert_eq!(
            data.pointer("/next_actions/lease/required")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert!(
            data.get("blockers")
                .and_then(Value::as_array)
                .expect("self-heal-plan blockers must be an array")
                .iter()
                .any(|blocker| {
                    blocker.get("kind").and_then(Value::as_str) == Some("lease")
                        && blocker.get("code").and_then(Value::as_str) == Some("lab_lease_required")
                })
        );
    }

