    #[test]
    fn session_validation_plan_reports_deferred_live_policy_without_device_work() {
        let result = run_cli(["--json", "session", "validation-plan", "--local"], true);

        assert_eq!(result.exit_code(), 0);
        let data = result.envelope.data.as_ref().unwrap();
        assert_eq!(
            data.get("schema_version").and_then(Value::as_str),
            Some("session.validation_plan.v0.1")
        );
        assert_eq!(
            data.get("live_validation_status").and_then(Value::as_str),
            Some("deferred")
        );
        assert_eq!(
            data.get("deferred_code").and_then(Value::as_str),
            Some("requires-live-device")
        );
        assert_eq!(
            data.pointer("/policy/no_fake_live_results")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/guarantees/does_not_touch_device")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert_eq!(
            data.pointer("/guarantees/does_not_read_resource_repositories")
                .and_then(Value::as_bool),
            Some(true)
        );
        let phase_matrix = data
            .get("phase_acceptance_matrix")
            .and_then(Value::as_array)
            .unwrap();
        for phase in ["A", "B", "C", "D", "cross_cutting"] {
            assert!(
                phase_matrix
                    .iter()
                    .any(|item| item.get("phase").and_then(Value::as_str) == Some(phase)),
                "missing validation phase {phase}"
            );
        }
        assert_eq!(
            data.pointer(
                "/ak_stale_capture_validation/classification/must_not_classify_as_game_freeze_from_adb_screencap_alone"
            )
            .and_then(Value::as_bool),
            Some(true)
        );
        assert!(
            data.pointer("/ak_stale_capture_validation/preferred_backend_order")
                .and_then(Value::as_array)
                .unwrap()
                .iter()
                .any(|backend| backend.as_str() == Some("nemu_ipc"))
        );
        assert_eq!(
            data.pointer("/pending_live_acceptance/title")
                .and_then(Value::as_str),
            Some("待真机验收")
        );
        assert_eq!(
            data.pointer("/pending_live_acceptance/must_not_be_marked_passed_by_offline_checks")
                .and_then(Value::as_bool),
            Some(true)
        );
        let pending_live_items = data
            .pointer("/pending_live_acceptance/items")
            .and_then(Value::as_array)
            .unwrap();
        assert!(
            pending_live_items
                .iter()
                .any(|item| item.get("id").and_then(Value::as_str)
                    == Some("ak_stale_capture_fresh_frame_recovery_validation"))
        );
        assert!(pending_live_items.iter().all(|item| {
            item.get("deferred_code").and_then(Value::as_str) == Some("requires-live-device")
        }));
        assert_eq!(
            data.pointer("/next_actions/schema_version")
                .and_then(Value::as_str),
            Some("session.validation_next_actions.v0.1")
        );
        assert_eq!(
            data.pointer("/next_actions/status").and_then(Value::as_str),
            Some("deferred")
        );
        assert_eq!(
            data.pointer("/next_actions/ordered/0/action")
                .and_then(Value::as_str),
            Some("review_pending_live_acceptance")
        );
        assert_eq!(
            data.pointer("/next_actions/pending_live_acceptance/item_count")
                .and_then(Value::as_u64),
            Some(pending_live_items.len() as u64)
        );
        assert_eq!(
            data.pointer("/next_actions/phase_c/self_heal")
                .and_then(Value::as_str),
            Some("observe_first_plan_review")
        );
        assert_eq!(
            data.pointer("/next_actions/phase_c/interaction_flow")
                .and_then(Value::as_str),
            Some("stream_plan_review")
        );
        assert_eq!(
            data.pointer("/next_actions/phase_c/trusted_channel")
                .and_then(Value::as_str),
            Some("transport_plan_review")
        );
        assert_eq!(
            data.pointer("/next_actions/guarantees/does_not_mark_live_validation_passed")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert!(
            data.get("deferred_live_tasks")
                .and_then(Value::as_array)
                .unwrap()
                .iter()
                .all(|task| task.get("deferred_code").and_then(Value::as_str)
                    == Some("requires-live-device"))
        );
    }

