    #[test]
    fn session_lease_enforces_holder_and_lease_id_on_release() {
        let _guard = ENV_LOCK.lock().unwrap();
        let temp = TempDir::new().unwrap();
        let acquire = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "lease",
                "acquire",
                "--state-dir",
                temp.path().to_str().unwrap(),
                "--holder",
                "scheduler",
                "--lease-id",
                "lease-1",
            ],
            true,
        );
        assert_eq!(acquire.exit_code(), 0);
        assert_eq!(
            acquire
                .envelope
                .data
                .as_ref()
                .unwrap()
                .pointer("/lease/holder")
                .and_then(Value::as_str),
            Some("scheduler")
        );

        let conflict = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "lease",
                "acquire",
                "--state-dir",
                temp.path().to_str().unwrap(),
                "--holder",
                "lab",
            ],
            true,
        );
        assert_eq!(conflict.exit_code(), 3);
        assert_eq!(
            conflict.envelope.error.as_ref().unwrap().code,
            "lease_conflict"
        );

        let wrong_holder = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "lease",
                "release",
                "--state-dir",
                temp.path().to_str().unwrap(),
                "--holder",
                "lab",
            ],
            true,
        );
        assert_eq!(wrong_holder.exit_code(), 3);
        assert_eq!(
            wrong_holder.envelope.error.as_ref().unwrap().code,
            "lease_holder_mismatch"
        );

        let wrong_id = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "lease",
                "release",
                "--state-dir",
                temp.path().to_str().unwrap(),
                "--holder",
                "scheduler",
                "--lease-id",
                "other",
            ],
            true,
        );
        assert_eq!(wrong_id.exit_code(), 3);
        assert_eq!(
            wrong_id.envelope.error.as_ref().unwrap().code,
            "lease_id_mismatch"
        );

        let released = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "lease",
                "release",
                "--state-dir",
                temp.path().to_str().unwrap(),
                "--holder",
                "scheduler",
                "--lease-id",
                "lease-1",
            ],
            true,
        );
        assert_eq!(released.exit_code(), 0);
        assert_eq!(
            released
                .envelope
                .data
                .as_ref()
                .unwrap()
                .get("status")
                .and_then(Value::as_str),
            Some("released")
        );
    }

    #[test]
    fn session_lease_touch_updates_matching_lease_timestamp() {
        let _guard = ENV_LOCK.lock().unwrap();
        let temp = TempDir::new().unwrap();
        let mut lease = new_session_lease(
            "ak".to_string(),
            "scheduler".to_string(),
            Some("lease-1".to_string()),
            false,
            None,
        );
        lease.acquired_at_unix_ms = 10;
        lease.updated_at_unix_ms = 20;
        let lease_path = session_lease_path(temp.path(), "ak");
        write_json_file_atomic(&lease_path, &lease).unwrap();

        let result = run_cli(
            [
                "--json",
                "--instance",
                "ak",
                "session",
                "lease",
                "touch",
                "--state-dir",
                temp.path().to_str().unwrap(),
                "--holder",
                "scheduler",
                "--lease-id",
                "lease-1",
            ],
            true,
        );

        assert_eq!(result.exit_code(), 0);
        let data = result.envelope.data.as_ref().unwrap();
        assert_eq!(
            data.get("schema_version").and_then(Value::as_str),
            Some("session.lease_touch.v0.1")
        );
        assert_eq!(data.get("status").and_then(Value::as_str), Some("touched"));
        assert_eq!(
            data.get("previous_updated_at_unix_ms")
                .and_then(Value::as_u64),
            Some(20)
        );
        assert_eq!(
            data.pointer("/lease/acquired_at_unix_ms")
                .and_then(Value::as_u64),
            Some(10)
        );
        assert!(
            data.pointer("/lease/updated_at_unix_ms")
                .and_then(Value::as_u64)
                .unwrap()
                > 20
        );
        let stored = read_json_file::<SessionLease>(&lease_path)
            .unwrap()
            .unwrap();
        assert_eq!(stored.acquired_at_unix_ms, 10);
        assert!(stored.updated_at_unix_ms > 20);
    }

